globalThis.__BQ = {"helikaz":{"ilkokul":{"kolay":[{"q":"Helikaz enziminin DNA üzerinde yaptığı temel iş nedir?","steps":[{"t":"Enzimi tanıyalım","a":"Helikaz bir görevli moleküldür","d":"Hücrede DNA ile ilgili işleri yapan küçük çalışan moleküllere enzim denir. Helikaz da bu enzimlerden biridir ve DNA üzerinde özel bir görev üstlenir."},{"t":"Görevi belirleyelim","a":"DNA sarmalını açar","d":"DNA iki ipliğin birbirine sarılmasıyla oluşur. Helikaz bu iki ipliği birbirinden ayırarak DNA sarmalını açar."}],"ans":"Helikaz, birbirine sarılı iki DNA ipliğini ayırarak DNA sarmalını açar."},{"q":"DNA kaç iplikten oluşur ve helikaz bu iplikleri ne yapar?","steps":[{"t":"İplik sayısını bulalım","a":"DNA iki iplikten oluşur","d":"DNA molekülü iki ayrı ipliğin birbirine dolanmasıyla meydana gelir. Bu yapı bir merdivene benzetilebilir."},{"t":"Helikazın işi","a":"İki ipliği ayırır","d":"Helikaz, birbirine sarılı olan bu iki ipliği yavaş yavaş birbirinden uzaklaştırır. Böylece iplikler ayrılmış olur."}],"ans":"DNA iki iplikten oluşur ve helikaz bu iki ipliği birbirinden ayırır."},{"q":"Helikaz DNA sarmalını açmasaydı DNA kopyalanabilir miydi?","steps":[{"t":"Kopyalama için ne gerekir","a":"İpliklerin açık olması gerekir","d":"DNA kopyalanırken iki ipliğin açık olması gerekir. Çünkü her iplik yeni iplik yapımı için örnek olarak kullanılır."},{"t":"Helikaz olmazsa","a":"Sarmal kapalı kalır","d":"Helikaz olmazsa DNA sarmalı kapalı kalır ve iplikler ayrılamaz. Bu durumda kopyalama başlayamaz."}],"ans":"Hayır, helikaz sarmalı açmasaydı iplikler ayrılamaz ve DNA kopyalanamazdı."},{"q":"Helikaz DNA merdiveninin neresini açar?","steps":[{"t":"DNA merdivenini düşünelim","a":"Basamaklar ortadadır","d":"DNA bir merdivene benzer. İki yan iplik kenarları, ortadaki bağlar ise basamakları oluşturur."},{"t":"Helikazın açtığı yer","a":"Ortadaki bağları açar","d":"Helikaz, merdivenin ortasındaki basamakları yani iki ipliği birbirine bağlayan kısımları açar. Böylece iplikler ortadan ayrılır."}],"ans":"Helikaz, DNA merdiveninin ortasındaki bağları açarak iki ipliği ayırır."},{"q":"Helikaz çalışırken DNA ipliklerine ne olur?","steps":[{"t":"Başlangıç durumu","a":"İplikler kapalı ve sarılıdır","d":"Helikaz çalışmaya başlamadan önce iki DNA ipliği birbirine sıkıca sarılmıştır. Bu yapı kapalıdır."},{"t":"Helikaz sonrası","a":"İplikler açılır","d":"Helikaz iplikler arasında ilerledikçe iplikler birbirinden ayrılır ve açılır. Açılan kısım kopyalanmaya hazır hale gelir."}],"ans":"Helikaz çalışınca kapalı olan iki DNA ipliği açılır ve birbirinden ayrılır."}],"zor":[{"q":"Helikaz iki ipliği ayırırken oluşan Y şeklindeki açık bölgeye ne ad verilir?","steps":[{"t":"Açılan bölgeyi görelim","a":"İplikler ayrılınca boşluk oluşur","d":"Helikaz iki ipliği ayırdıkça açık bir bölge meydana gelir. Bu bölgede iki iplik birbirinden uzaklaşmıştır."},{"t":"Şekli adlandıralım","a":"Y harfine benzer","d":"Açılan bu bölge Y harfine veya çatallı bir yola benzer. Bu nedenle bu bölgeye replikasyon çatalı denir."}],"ans":"Helikazın açtığı bu Y şeklindeki bölgeye replikasyon çatalı denir."},{"q":"Helikaz DNA üzerinde tek bir yerde mi yoksa birçok yerde mi sarmalı açar?","steps":[{"t":"DNA uzunluğunu düşünelim","a":"DNA çok uzundur","d":"DNA molekülü çok uzun bir iplik gibidir. Tek bir noktadan başlayıp baştan sona açmak çok uzun zaman alırdı."},{"t":"Helikazın çalışması","a":"Birçok noktada açar","d":"İşi hızlandırmak için helikaz DNA üzerinde birçok farklı noktada sarmalı açar. Böylece kopyalama her yerde aynı anda başlar."}],"ans":"Helikaz DNA üzerinde birçok farklı noktada sarmalı açar, böylece kopyalama hızlanır."},{"q":"Helikaz iki ipliği birbirine tutan bağları kopardıktan sonra ipliklerin tekrar kapanmaması nasıl sağlanır?","steps":[{"t":"Sorunu görelim","a":"İplikler tekrar kapanmak ister","d":"Helikaz iplikleri ayırdıktan sonra iplikler kendiliğinden tekrar birbirine yapışmaya çalışır. Bu istenmeyen bir durumdur."},{"t":"Çözümü bulalım","a":"Yardımcı moleküller tutar","d":"Açılan iplikleri açık tutan yardımcı moleküller iplikleri kenarda bekletir. Böylece iplikler kapanmaz ve kopyalama rahatça yapılır."}],"ans":"Yardımcı moleküller açılan iplikleri tutarak tekrar kapanmasını engeller."},{"q":"Helikaz işini bitirdikten sonra hücrede DNA kopyalama hangi aşamaya geçer?","steps":[{"t":"Helikazın işi","a":"Sarmalı açmaktır","d":"Helikazın görevi iki ipliği ayırıp sarmalı açmaktır. İplikler açıldığında helikazın asıl görevi tamamlanmış olur."},{"t":"Sonraki aşama","a":"Yeni iplik yapımı başlar","d":"Açılan ipliklerin her biri örnek olarak kullanılır. Başka enzimler bu ipliklerin karşısına yeni iplikler yapmaya başlar."}],"ans":"Helikaz sarmalı açtıktan sonra açılan ipliklerin karşısına yeni iplik yapımı başlar."},{"q":"Helikaz neden DNA kopyalanmasının başında çalışır?","steps":[{"t":"Kopyalamanın ilk şartı","a":"İplikler açık olmalı","d":"DNA kopyalanmadan önce iki ipliğin ayrılıp açık hale gelmesi gerekir. Kapalı sarmalda kopyalama yapılamaz."},{"t":"Helikazın sırası","a":"En önce çalışır","d":"Sarmalı açan enzim helikaz olduğu için diğer enzimlerden önce çalışması gerekir. Bu yüzden helikaz kopyalamanın başında görev alır."}],"ans":"Çünkü kopyalama başlamadan önce iplikleri açan helikaz en başta çalışmalıdır."}]},"ortaokul":{"kolay":[{"q":"Helikaz enzimi DNA çift sarmalını açarken iki ipliği bir arada tutan hangi yapıları koparır?","steps":[{"t":"İplikleri tutan yapıyı bulalım","a":"İki iplik bağlarla bağlıdır","d":"DNA çift sarmalında iki iplik karşılıklı bazlar arasındaki bağlarla bir arada tutulur. Bu bağlar zayıf ama çok sayıdadır."},{"t":"Bağın adını öğrenelim","a":"Hidrojen bağları","d":"Karşılıklı bazlar arasındaki bu bağlara hidrojen bağı denir. Helikaz bu hidrojen bağlarını koparır."}],"ans":"Helikaz, iki ipliği bir arada tutan hidrojen bağlarını koparır."},{"q":"Helikazın çalışması sonucunda oluşan replikasyon çatalı nasıl bir yapıdır?","steps":[{"t":"Çatalın oluşumu","a":"İplikler ayrılır","d":"Helikaz ilerledikçe iki iplik birbirinden ayrılır ve açık bir bölge oluşur. Bu bölgenin önünde sarmal hâlâ kapalıdır."},{"t":"Şeklini tanımlayalım","a":"Y şeklindedir","d":"Açılmış iki iplik ile kapalı kısım birleşince Y harfine benzer bir görünüm oluşur. Bu yapıya replikasyon çatalı denir."}],"ans":"Replikasyon çatalı, helikazın iplikleri ayırmasıyla oluşan Y şeklindeki açık yapıdır."},{"q":"Helikaz çalışmadan DNA polimeraz enzimi görevini yapabilir mi?","steps":[{"t":"DNA polimerazın ihtiyacı","a":"Açık kalıp iplik gerekir","d":"DNA polimeraz yeni iplik yaparken örnek olarak açık bir kalıp ipliğe ihtiyaç duyar. Kapalı sarmalda kalıp iplik okunamaz."},{"t":"Helikazın rolü","a":"Kalıbı açar","d":"Helikaz sarmalı açarak kalıp iplikleri ortaya çıkarır. Bu yapılmadan DNA polimeraz çalışamaz."}],"ans":"Hayır, helikaz sarmalı açıp kalıbı hazırlamadan DNA polimeraz çalışamaz."},{"q":"Helikaz enzimi çalışırken enerji kullanır mı?","steps":[{"t":"İşin zorluğunu düşünelim","a":"Bağ koparmak iş gerektirir","d":"Hidrojen bağlarını koparmak ve iplikleri ayırmak kolay bir iş değildir. Bu işin yapılabilmesi için enerji gereklidir."},{"t":"Enerji kaynağı","a":"Hücre enerjisi kullanılır","d":"Helikaz bu işi yaparken hücredeki enerji moleküllerini kullanır. Yani helikaz enerji harcayan bir enzimdir."}],"ans":"Evet, helikaz iplikleri ayırırken hücredeki enerjiyi kullanır."},{"q":"Helikaz DNA üzerinde hangi noktadan çalışmaya başlar?","steps":[{"t":"Başlangıç noktası","a":"Özel bölgeler vardır","d":"DNA üzerinde kopyalamanın başlayacağı belirli bölgeler bulunur. Bu bölgelere replikasyon başlangıç noktaları denir."},{"t":"Helikazın yeri","a":"Başlangıç noktasından açar","d":"Helikaz bu başlangıç noktalarına gelir ve sarmalı buradan açmaya başlar. Açılma iki yöne doğru ilerleyebilir."}],"ans":"Helikaz, DNA üzerindeki replikasyon başlangıç noktalarından çalışmaya başlar."}],"zor":[{"q":"Helikaz hidrojen bağlarını koparırken adenin-timin ile guanin-sitozin çiftlerinden hangisi daha kolay açılır?","steps":[{"t":"Bağ sayılarını bulalım","a":"A-T ikili, G-C üçlü bağ","d":"Adenin ile timin arasında iki hidrojen bağı bulunur. Guanin ile sitozin arasında ise üç hidrojen bağı vardır."},{"t":"Hangisi kolay açılır","a":"Az bağlı olan kolay açılır","d":"Daha az hidrojen bağı olan çiftin açılması daha az enerji gerektirir. Bu nedenle adenin-timin çifti daha kolay açılır."},{"t":"Sonucu yorumlayalım","a":"A-T bakımından zengin bölgeler","d":"Adenin ve timin bakımından zengin bölgeler daha kolay açıldığı için replikasyon genellikle bu tür bölgelerden başlar."}],"ans":"İki hidrojen bağı içerdiği için adenin-timin çifti, guanin-sitozin çiftinden daha kolay açılır."},{"q":"Helikaz çift yönlü olarak çalıştığında bir başlangıç noktasından kaç replikasyon çatalı oluşur?","steps":[{"t":"Açılma yönünü düşünelim","a":"İki yöne açılır","d":"Helikaz başlangıç noktasından hem sağa hem sola doğru açılma yapabilir. Bu durumda açılma iki ayrı yönde ilerler."},{"t":"Çatal sayısını bulalım","a":"Her yön bir çatal","d":"Her açılma yönünde ayrı bir Y şeklindeki çatal oluşur. İki yön olduğu için iki çatal meydana gelir."},{"t":"Sonuç","a":"İki çatal","d":"Böylece tek bir başlangıç noktasından iki replikasyon çatalı ortaya çıkar. Bu kopyalamayı hızlandırır."}],"ans":"Çift yönlü çalışan helikaz, bir başlangıç noktasından iki replikasyon çatalı oluşturur."},{"q":"İnsan gibi büyük DNA moleküllerinde helikazın birçok noktada çalışmasının avantajı nedir?","steps":[{"t":"DNA uzunluğunu düşünelim","a":"DNA çok uzundur","d":"İnsan hücresindeki DNA milyonlarca baz çiftinden oluşur ve çok uzundur. Tek noktadan kopyalamak çok uzun sürerdi."},{"t":"Çok noktadan başlama","a":"Aynı anda açılır","d":"Helikaz birçok başlangıç noktasında aynı anda sarmalı açar. Böylece kopyalama birçok bölgede paralel olarak yürütülür."},{"t":"Avantajı belirleyelim","a":"Süre kısalır","d":"Aynı anda çok bölgede çalışmak toplam kopyalama süresini büyük ölçüde kısaltır. Bu da hücre bölünmesini hızlandırır."}],"ans":"Birçok noktada aynı anda açılma sağlandığı için uzun DNA çok daha kısa sürede kopyalanır."},{"q":"Helikazın açtığı iplikler tek iplik bağlayıcı proteinler tarafından tutulmasaydı ne tür bir sorun yaşanırdı?","steps":[{"t":"Açık ipliklerin eğilimi","a":"Tekrar birleşme isteği","d":"Helikaz ayırdığı iki iplik, karşılıklı bazlar arasındaki çekim nedeniyle tekrar birleşmeye eğilimlidir. Ayrıca tek iplikler kendi içinde de katlanabilir."},{"t":"Bağlayıcı proteinin görevi","a":"İplikleri açık tutar","d":"Tek iplik bağlayıcı proteinler açılmış ipliklere bağlanarak onları düz ve açık tutar. Böylece iplikler tekrar kapanamaz."},{"t":"Eksik olursa","a":"Kalıp okunamaz","d":"Bu proteinler olmasaydı iplikler tekrar kapanır veya katlanırdı. Bu durumda DNA polimeraz kalıbı düzgün okuyamaz ve kopyalama aksardı."}],"ans":"Tek iplik bağlayıcı proteinler olmasaydı açılan iplikler tekrar kapanır veya katlanır, kopyalama aksardı."},{"q":"Helikaz neden replikasyonun en başında, diğer enzimlerden önce çalışmak zorundadır?","steps":[{"t":"Diğer enzimlerin ihtiyacı","a":"Açık iplik gerektirir","d":"Primer yapan ve yeni iplik ekleyen enzimler ancak açık kalıp iplik üzerinde çalışabilir. Kapalı sarmalda bu enzimler iş yapamaz."},{"t":"Helikazın görevi","a":"Sarmalı açar","d":"Sarmalı açıp kalıp iplikleri ortaya çıkaran tek enzim helikazdır. Diğer enzimlerin çalışması için bu açılma şarttır."},{"t":"Sıralamayı belirleyelim","a":"Helikaz en önce","d":"Bu nedenle helikaz mutlaka diğer enzimlerden önce çalışmalıdır. Helikaz çalışmadan replikasyon hiç başlayamaz."}],"ans":"Diğer enzimler açık kalıp gerektirdiğinden, sarmalı açan helikaz mutlaka en başta çalışmalıdır."}]},"lise":{"kolay":[{"q":"Helikaz enziminin replikasyondaki temel işlevini ve etkilediği bağ türünü açıklayınız.","steps":[{"t":"Enzimin işlevi","a":"Çift sarmalı açar","d":"Helikaz, DNA replikasyonunun başında çift sarmalı oluşturan iki ipliği birbirinden ayırır. Bu sayede kalıp iplikler ortaya çıkar."},{"t":"Etkilenen bağ","a":"Hidrojen bağları","d":"İki ipliği bir arada tutan, karşılıklı bazlar arasındaki hidrojen bağlarıdır. Helikaz bu hidrojen bağlarını koparır."},{"t":"Sonucu belirleyelim","a":"Replikasyon çatalı","d":"Bağların kopması ve ipliklerin ayrılmasıyla replikasyon çatalı oluşur. Böylece kopyalama başlayabilir."}],"ans":"Helikaz, bazlar arasındaki hidrojen bağlarını koparıp çift sarmalı açarak replikasyon çatalını oluşturur."},{"q":"Replikasyon çatalının yapısını ve helikazın bu yapıdaki konumunu açıklayınız.","steps":[{"t":"Çatalın oluşumu","a":"İplikler ayrılır","d":"Helikaz ilerledikçe çift sarmal açılır ve iki tek iplik ortaya çıkar. Çatalın gerisinde iplikler ayrılmış, önünde ise hâlâ sarmaldır."},{"t":"Şekli tanımlayalım","a":"Y benzeri yapı","d":"Açılmış iki iplik ile kapalı sarmalın birleştiği bölge Y harfine benzer. Bu yapıya replikasyon çatalı denir."},{"t":"Helikazın konumu","a":"Çatalın ucunda","d":"Helikaz, çatalın açıldığı uç noktada yer alır ve önündeki sarmalı açmaya devam eder. Çatal helikaz ilerledikçe ileriye doğru hareket eder."}],"ans":"Replikasyon çatalı Y şeklinde bir yapıdır ve helikaz, çatalın açılma ucunda yer alarak sarmalı ilerleterek açar."},{"q":"Helikazın çalışması için neden enerji gerektiğini açıklayınız.","steps":[{"t":"İşin niteliği","a":"Bağ koparma işi","d":"Helikaz çok sayıda hidrojen bağını koparmak ve iplikleri ayırmak zorundadır. Bu işlemler kendiliğinden ve enerjisiz gerçekleşmez."},{"t":"Enerji kaynağı","a":"ATP kullanılır","d":"Helikaz, hücrenin enerji molekülü olan ATP yi kullanarak iş yapar. ATP nin parçalanmasıyla açığa çıkan enerji kullanılır."},{"t":"Enzim türü","a":"Aktif çalışan enzim","d":"Bu nedenle helikaz, enerji harcayarak DNA boyunca ilerleyen aktif bir enzimdir. Enerji olmadan sarmalı açamaz."}],"ans":"Helikaz hidrojen bağlarını koparıp iplikleri ayırmak için ATP enerjisi kullanır."},{"q":"Helikaz enziminin DNA polimeraz enzimi için neden ön koşul olduğunu açıklayınız.","steps":[{"t":"DNA polimerazın ihtiyacı","a":"Açık kalıp gerektirir","d":"DNA polimeraz, yeni iplik sentezlerken kalıp olarak tek iplik halinde açılmış bir DNA ipliğine ihtiyaç duyar. Çift sarmalı kalıp olarak okuyamaz."},{"t":"Helikazın sağladığı","a":"Tek iplikli kalıp","d":"Helikaz sarmalı açarak iki ipliği tek iplik haline getirir. Bu açık kalıplar DNA polimerazın okuyabileceği yapıdır."},{"t":"İlişkiyi belirleyelim","a":"Önce helikaz çalışır","d":"Dolayısıyla helikaz çalışıp kalıbı hazırlamadan DNA polimeraz iş yapamaz. Helikaz bu enzim için ön koşuldur."}],"ans":"DNA polimeraz tek iplikli kalıp gerektirdiğinden, sarmalı açan helikaz onun için ön koşuldur."},{"q":"Replikasyonun çift yönlü ilerlemesinde helikazın rolünü açıklayınız.","steps":[{"t":"Başlangıç noktası","a":"Ori bölgesi","d":"Replikasyon, DNA üzerindeki başlangıç noktası olan ori bölgesinden başlar. Helikaz buraya yerleşerek açılmayı başlatır."},{"t":"İki yöne açılma","a":"Zıt yönlerde ilerler","d":"Helikaz başlangıç noktasından iki zıt yöne doğru sarmalı açar. Böylece iki ayrı replikasyon çatalı oluşur."},{"t":"Sonuç","a":"Hızlı kopyalama","d":"İki yönde aynı anda açılma, DNA nın daha hızlı kopyalanmasını sağlar. Bu da replikasyon süresini kısaltır."}],"ans":"Helikaz başlangıç noktasından iki zıt yöne açılarak çift yönlü replikasyonu sağlar."},{"q":"Tek iplik bağlayıcı proteinlerin helikazla birlikte çalışmasındaki işlevini açıklayınız.","steps":[{"t":"Açık ipliklerin sorunu","a":"Tekrar birleşme eğilimi","d":"Helikazın ayırdığı iki iplik, baz çekimleri nedeniyle yeniden birleşmeye eğilimlidir. Ayrıca tek iplikler kendi içinde de katlanabilir."},{"t":"Proteinin görevi","a":"İplikleri açık tutar","d":"Tek iplik bağlayıcı proteinler açılmış ipliklere bağlanır ve onları düz, açık halde tutar. Böylece iplikler tekrar kapanamaz."},{"t":"Birlikte çalışma","a":"Kalıbı korur","d":"Helikaz açma işini yaparken bu proteinler açık kalıbı korur. Böylece kopyalama enzimleri kalıbı düzgün okuyabilir."}],"ans":"Tek iplik bağlayıcı proteinler, helikazın açtığı iplikleri açık tutarak tekrar kapanmasını engeller."},{"q":"Helikaz enziminin etkisiyle açığa çıkan iki ipliğin neden ayrı ayrı kalıp olarak kullanılabildiğini açıklayınız.","steps":[{"t":"İpliklerin yapısı","a":"Birbirini tamamlar","d":"DNA nın iki ipliği birbirini tamamlayan baz dizilerine sahiptir. Yani bir ipliğin dizisi diğerinin dizisini belirler."},{"t":"Helikaz açar","a":"İki kalıp ortaya çıkar","d":"Helikaz iplikleri ayırınca her iki iplik de açıkta kalır. Her biri kendi karşıt ipliğini yapmak için kalıp olur."},{"t":"Sonuç","a":"Yarı korunumlu kopyalama","d":"Her iplik ayrı kalıp olduğu için yeni DNA larda biri eski biri yeni iplik bulunur. Bu nedenle replikasyon yarı korunumludur."}],"ans":"Helikaz iplikleri ayırınca, birbirini tamamlayan her iki iplik de ayrı birer kalıp olarak kullanılabilir."},{"q":"Helikazın replikasyon başlangıç noktalarını seçmesinin önemini açıklayınız.","steps":[{"t":"Başlangıç noktaları","a":"Belirli bölgeler","d":"Replikasyon rastgele yerlerden değil, DNA üzerindeki belirli başlangıç bölgelerinden başlar. Bu bölgeler özel baz dizilerine sahiptir."},{"t":"Helikazın seçimi","a":"Bu bölgelere yerleşir","d":"Helikaz bu başlangıç bölgelerine yerleşerek açılmayı buradan başlatır. Genellikle kolay açılan bölgeler tercih edilir."},{"t":"Önemi","a":"Düzenli kopyalama","d":"Belirli noktalardan başlamak, kopyalamanın düzenli ve eksiksiz olmasını sağlar. Böylece DNA nın tamamı doğru şekilde kopyalanır."}],"ans":"Helikaz belirli başlangıç noktalarından açılmayı başlatarak kopyalamanın düzenli ve eksiksiz olmasını sağlar."},{"q":"Adenin-timin bakımından zengin bölgelerin replikasyon başlangıcı için neden uygun olduğunu açıklayınız.","steps":[{"t":"Bağ sayısı","a":"A-T iki bağ içerir","d":"Adenin ile timin arasında iki hidrojen bağı vardır. Guanin ile sitozin arasında ise üç hidrojen bağı bulunur."},{"t":"Açılma kolaylığı","a":"Az bağ kolay açılır","d":"Daha az hidrojen bağı içeren bölgeler daha az enerjiyle açılır. Bu nedenle A-T zengini bölgeler daha kolay ayrılır."},{"t":"Sonuç","a":"Başlangıç için uygun","d":"Kolay açıldıkları için A-T zengini bölgeler replikasyon başlangıcı için uygundur. Helikaz buralarda daha rahat çalışır."}],"ans":"A-T çiftleri iki hidrojen bağı içerdiği için kolay açılır ve bu bölgeler replikasyon başlangıcı için uygundur."},{"q":"Helikazın çalışmasının yarı korunumlu replikasyon ile ilişkisini açıklayınız.","steps":[{"t":"Yarı korunumlu kavramı","a":"Bir eski bir yeni iplik","d":"Yarı korunumlu replikasyonda her yeni DNA molekülü bir eski ve bir yeni iplikten oluşur. Eski iplik kalıp olarak korunur."},{"t":"Helikazın rolü","a":"İki kalıbı ayırır","d":"Helikaz iki eski ipliği ayırarak her birini ayrı kalıp haline getirir. Böylece her eski iplik korunarak kullanılır."},{"t":"İlişkiyi belirleyelim","a":"Ayırma şarttır","d":"İplikler ayrılmadan yarı korunumlu kopyalama olamaz. Helikazın açma işlevi bu modelin ilk adımıdır."}],"ans":"Helikaz iki eski ipliği ayırıp ayrı kalıplar oluşturarak yarı korunumlu replikasyonun temelini hazırlar."},{"q":"Helikazın replikasyon hızına etkisini açıklayınız.","steps":[{"t":"Sarmalı açma hızı","a":"Çatalı ilerletir","d":"Helikaz sarmalı ne kadar hızlı açarsa replikasyon çatalı o kadar hızlı ilerler. Açılma hızı kopyalama hızını sınırlar."},{"t":"Çok noktada çalışma","a":"Paralel açılma","d":"Helikaz birçok başlangıç noktasında aynı anda çalışarak açılmayı paralel hale getirir. Bu da toplam süreyi kısaltır."},{"t":"Sonuç","a":"Hız belirleyici","d":"Bu nedenle helikaz, replikasyon hızını belirleyen önemli bir enzimdir. Helikaz yavaşlarsa kopyalama da yavaşlar."}],"ans":"Helikaz sarmalı hızlı ve birçok noktada açarak replikasyon hızını artıran belirleyici bir enzimdir."},{"q":"Helikaz çalışırken DNA nın ileri kısmında oluşan gerilmenin neden sorun olduğunu açıklayınız.","steps":[{"t":"Açılmanın etkisi","a":"İleri kısımda burulma","d":"Helikaz sarmalı açtıkça önündeki kapalı bölgede iplikler daha fazla burulur. Bu durum DNA da gerginlik oluşturur."},{"t":"Sorunu görelim","a":"Aşırı gerilme oluşur","d":"Bu burulma ve gerginlik artarsa helikazın ilerlemesi zorlaşır. DNA aşırı gerilebilir ve hasar görebilir."},{"t":"Çözüm","a":"Topoizomeraz rahatlatır","d":"Topoizomeraz adlı enzim bu gerginliği gidererek DNA yı rahatlatır. Böylece helikaz çalışmaya devam edebilir."}],"ans":"Helikazın açması ileri bölgede burulma yaratır; bu gerilme sorun çıkarmasın diye topoizomeraz DNA yı rahatlatır."},{"q":"Helikaz enziminin DNA boyunca tek yönde mi yoksa rastgele mi ilerlediğini açıklayınız.","steps":[{"t":"İlerleme düzeni","a":"Belirli yönde ilerler","d":"Helikaz bağlandığı kalıp iplik boyunca belirli bir yönde ilerler. Rastgele değil, düzenli bir biçimde hareket eder."},{"t":"Çatalla ilişkisi","a":"Çatalı açar","d":"Helikaz ilerledikçe replikasyon çatalını önüne doğru açar. Hareket yönü çatalın açılma yönünü belirler."},{"t":"Sonuç","a":"Yönlü hareket","d":"Bu yönlü ve düzenli hareket sayesinde kopyalama belirli bir sırayla yapılır. Böylece DNA eksiksiz açılır."}],"ans":"Helikaz rastgele değil, kalıp iplik boyunca belirli bir yönde düzenli olarak ilerler ve çatalı açar."},{"q":"Helikazın görevini tamamladıktan sonra replikasyonun nasıl devam ettiğini açıklayınız.","steps":[{"t":"Helikazın görevi","a":"Kalıbı açar","d":"Helikaz sarmalı açıp tek iplikli kalıpları ortaya çıkarınca asıl görevini tamamlar. Artık kalıplar kopyalanmaya hazırdır."},{"t":"Primer yapımı","a":"Primaz çalışır","d":"Açık kalıp üzerine primaz enzimi kısa RNA primerleri yerleştirir. Bu primerler yeni iplik yapımının başlamasını sağlar."},{"t":"İplik sentezi","a":"DNA polimeraz ekler","d":"DNA polimeraz primerden başlayarak kalıbı okur ve yeni nükleotitleri ekler. Böylece yeni iplik sentezlenir."}],"ans":"Helikaz kalıbı açtıktan sonra primaz primer ekler ve DNA polimeraz yeni ipliği sentezleyerek replikasyon devam eder."},{"q":"Helikaz enzimi olmayan bir hücrede replikasyonun neden gerçekleşemeyeceğini açıklayınız.","steps":[{"t":"Helikazın işlevi","a":"Tek açan enzim","d":"Çift sarmalı açıp iplikleri ayıran enzim helikazdır. Bu işi yapan başka bir temel mekanizma replikasyonda yoktur."},{"t":"Sonraki adımlar","a":"Açık kalıp gerektirir","d":"Primaz ve DNA polimeraz gibi enzimler çalışmak için açık tek iplikli kalıp ister. Kapalı sarmalda bu enzimler iş yapamaz."},{"t":"Sonuç","a":"Replikasyon olmaz","d":"Helikaz olmadan sarmal açılamaz ve kalıp hazırlanamaz. Bu durumda replikasyon hiç başlayamaz."}],"ans":"Helikaz olmadan çift sarmal açılamaz, kalıp hazırlanamaz ve replikasyon hiç başlayamaz."}],"zor":[{"q":"Helikazın açtığı çift sarmalın ileri bölgesinde oluşan pozitif süpersarımın replikasyona etkisini ve nasıl giderildiğini açıklayınız.","steps":[{"t":"Süpersarımın oluşumu","a":"İleri bölgede burulma","d":"Helikaz iplikleri ayırırken sarmalın ileri bölgesinde fazladan dönüş yani pozitif süpersarım birikir. Bu, sarmalın aşırı sıkışmasına neden olur."},{"t":"Replikasyona etkisi","a":"Helikazı yavaşlatır","d":"Biriken süpersarım helikazın ilerlemesini zorlaştırır ve durdurabilir. Aşırı gerginlik DNA hasarına da yol açabilir."},{"t":"Giderilme yolu","a":"Topoizomeraz keser","d":"Topoizomeraz enzimi iplikleri geçici olarak keserek dönüşü serbest bırakır ve gerginliği giderir. Sonra kesik uçları tekrar birleştirir."},{"t":"Sonuç","a":"Akıcı replikasyon","d":"Süpersarım giderilince helikaz rahatça ilerler ve replikasyon kesintisiz sürer. Böylece kopyalama hızı korunur."}],"ans":"Helikazın oluşturduğu pozitif süpersarım helikazı yavaşlatır; topoizomeraz iplikleri kesip gerginliği gidererek replikasyonu sürdürür."},{"q":"Çift yönlü replikasyonda helikazın iki replikasyon çatalında zıt yönlerde ilerlemesinin kalıp ipliklerin okunmasına etkisini açıklayınız.","steps":[{"t":"İki çatalın oluşumu","a":"Ori den iki yöne","d":"Helikaz başlangıç noktası olan ori bölgesinden iki zıt yöne doğru açılır. Böylece iki ayrı replikasyon çatalı oluşur."},{"t":"Zıt yönlü ilerleme","a":"Farklı yönlerde açma","d":"Her çataldaki helikaz birbirine zıt yönde sarmalı açar. Bu, her çatalda kalıpların farklı yönlerde açığa çıkmasına neden olur."},{"t":"Kalıp okunmasına etkisi","a":"5 üç yönü değişmez","d":"DNA polimeraz daima 5 üç yönünde okuyup eklediği için, açılma yönüne göre bir iplik sürekli diğeri kesikli sentezlenir. Yön değişimi bu iş bölümünü belirler."},{"t":"Sonuç","a":"Sürekli ve kesikli iplik","d":"Böylece her çatalda hem sürekli hem kesikli iplik sentezi yürür. Bu, çift yönlü replikasyonun temel düzenidir."}],"ans":"Helikazın zıt yönlerde açması, her çatalda kalıpların farklı yönde açığa çıkmasına yol açar ve sürekli ile kesikli iplik sentezini belirler."},{"q":"Helikaz enziminin ATP bağımlı çalışmasının replikasyonun yönlü ve geri dönüşsüz ilerlemesine katkısını açıklayınız.","steps":[{"t":"ATP kullanımı","a":"Enerji harcar","d":"Helikaz her adımda ATP yi parçalayarak enerji elde eder. Bu enerji hidrojen bağlarını koparmak ve ilerlemek için kullanılır."},{"t":"Yönlü hareket","a":"Tek yönde itme","d":"ATP nin parçalanması helikazı kalıp boyunca belirli yönde iter. Bu sayede enzim ileri doğru düzenli hareket eder."},{"t":"Geri dönüşsüzlük","a":"Geri kaymayı engeller","d":"Harcanan enerji ilerlemeyi termodinamik olarak avantajlı kılar ve geri kaymayı engeller. Böylece açılan sarmal tekrar kapanmaz."},{"t":"Sonuç","a":"Kararlı ilerleme","d":"ATP bağımlı çalışma sayesinde replikasyon çatalı yönlü ve kararlı şekilde ilerler. Bu, kopyalamanın güvenilir olmasını sağlar."}],"ans":"ATP enerjisi helikazı tek yönde iterek geri kaymayı engeller; böylece replikasyon yönlü ve kararlı biçimde ilerler."},{"q":"Helikaz, primaz ve tek iplik bağlayıcı proteinlerin replikasyon çatalındaki eş güdümlü çalışmasını açıklayınız.","steps":[{"t":"Helikaz açar","a":"Kalıbı ortaya çıkarır","d":"Helikaz çatalın ucunda sarmalı açarak tek iplikli kalıpları ortaya çıkarır. Bu, diğer enzimler için zemin hazırlar."},{"t":"Bağlayıcı protein korur","a":"İplikleri açık tutar","d":"Açılan iplikler hemen tek iplik bağlayıcı proteinlerle kaplanır. Böylece iplikler tekrar kapanmaz ve katlanmaz."},{"t":"Primaz başlatır","a":"RNA primer koyar","d":"Primaz açık kalıp üzerine kısa RNA primerleri yerleştirir. Bu primerler DNA polimerazın başlaması için gereklidir."},{"t":"Eş güdüm","a":"Birlikte ilerler","d":"Bu üç bileşen çatalda uyum içinde çalışır; helikaz açar, protein korur, primaz başlatır. Bu eş güdüm sayesinde replikasyon kesintisiz yürür."}],"ans":"Helikaz kalıbı açar, bağlayıcı proteinler iplikleri açık tutar, primaz primer ekler; bu eş güdümle replikasyon çatalı kesintisiz ilerler."},{"q":"Helikazın çok sayıda replikasyon başlangıç noktasında çalışmasının ökaryot hücrelerdeki büyük genomların kopyalanmasına katkısını açıklayınız.","steps":[{"t":"Genom büyüklüğü","a":"Çok uzun DNA","d":"Ökaryot hücrelerde DNA milyonlarca hatta milyarlarca baz çiftinden oluşur. Tek noktadan kopyalamak günlerce sürerdi."},{"t":"Çok noktalı başlama","a":"Çok sayıda ori","d":"Genom üzerinde çok sayıda replikasyon başlangıç noktası bulunur. Her noktada bir helikaz açılmayı başlatır."},{"t":"Paralel çalışma","a":"Aynı anda kopyalama","d":"Çok sayıda çatal aynı anda ilerleyerek genomun farklı bölümleri paralel kopyalanır. Çatallar birbirine ulaşınca birleşir."},{"t":"Sonuç","a":"Süre kısalır","d":"Bu paralel çalışma sayesinde büyük genom makul sürede kopyalanır. Böylece hücre bölünmesi zamanında tamamlanır."}],"ans":"Çok sayıda noktada çalışan helikazlar paralel açılma sağlayarak büyük ökaryot genomlarının makul sürede kopyalanmasını mümkün kılar."},{"q":"Helikazın işlevi bozulursa replikasyon çatalının ilerlemesinde ve genom kopyalanmasında ne tür sorunlar oluşacağını açıklayınız.","steps":[{"t":"Helikazın işlevi","a":"Sarmalı açar","d":"Helikaz çatalın ucunda sarmalı açarak çatalın ilerlemesini sağlar. Açılma olmazsa çatal ileri gidemez."},{"t":"Bozulmanın etkisi","a":"Çatal durur","d":"Helikaz çalışmazsa replikasyon çatalı belirli bir noktada durur. Bu noktadan sonra kalıp açılamaz."},{"t":"Genoma etkisi","a":"Eksik kopyalama","d":"Çatalın durması o bölgenin kopyalanamamasına yol açar. Genomun bir kısmı eksik kalır ve bu hücre bölünmesini engeller."},{"t":"Sonuç","a":"Hücre zarar görür","d":"Eksik kopyalanan DNA mutasyonlara ve hücre ölümüne yol açabilir. Bu nedenle helikaz işlevi genom bütünlüğü için kritiktir."}],"ans":"Helikaz bozulursa çatal durur, ilgili bölge kopyalanamaz ve eksik genom hücre bölünmesini engelleyerek hasara yol açar."},{"q":"Helikazın çift sarmalı açma yönü ile DNA polimerazın 5 üç sentez yönü arasındaki uyumsuzluğun kesikli iplik sentezini nasıl gerektirdiğini açıklayınız.","steps":[{"t":"Helikazın açma yönü","a":"Çatalı tek yöne açar","d":"Helikaz replikasyon çatalını tek bir yönde sürekli açar. Bu, kalıpların belirli yönde açığa çıkmasını sağlar."},{"t":"Polimerazın kısıtı","a":"Sadece 5 üç eklenir","d":"DNA polimeraz nükleotitleri yalnızca 5 üç yönünde ekleyebilir. Bu nedenle iki kalıbı aynı yönde sürekli kopyalayamaz."},{"t":"Uyumsuzluk","a":"Bir iplik ters yönde","d":"Çatalın açılma yönü bir kalıpta polimerazla uyumludur, diğerinde terstir. Ters olan kalıp sürekli sentezlenemez."},{"t":"Sonuç","a":"Okazaki parçaları","d":"Ters yöndeki kalıp, kısa parçalar halinde geriye doğru sentezlenir; bunlara Okazaki parçaları denir. Böylece kesikli iplik oluşur."}],"ans":"Helikazın tek yönlü açması ile polimerazın 5 üç kısıtı uyuşmadığından, bir kalıp Okazaki parçaları halinde kesikli sentezlenir."},{"q":"Replikasyon çatallarının birbirine yaklaşıp birleşmesinde helikazların rolünü ve karşılaşma anında ne olduğunu açıklayınız.","steps":[{"t":"Çatalların ilerlemesi","a":"Birbirine doğru gider","d":"Komşu başlangıç noktalarından çıkan iki çatal birbirine doğru ilerler. Her çatalın önünde bir helikaz sarmalı açar."},{"t":"Yaklaşma","a":"Açık bölge azalır","d":"İki çatal yaklaştıkça aralarındaki kapalı sarmal bölgesi giderek azalır. Helikazlar bu bölgeyi açmaya devam eder."},{"t":"Karşılaşma","a":"Açılacak bölge biter","d":"İki helikaz karşılaştığında aradaki tüm sarmal açılmış olur. Açılacak bölge kalmadığında helikazlar görevlerini tamamlar."},{"t":"Sonuç","a":"Bölgeler birleşir","d":"Karşılaşma noktasında yeni sentezlenen iplikler birleştirilir. Böylece komşu replikasyon bölgeleri tek bir bütün haline gelir."}],"ans":"Komşu çatalların helikazları aradaki sarmalı açar; karşılaştıklarında açılacak bölge biter ve yeni iplikler birleştirilerek bölgeler bütünleşir."},{"q":"Helikazın açtığı tek iplikli bölgelerin neden hızlı korunması gerektiğini ve korunmazsa oluşabilecek hasarları açıklayınız.","steps":[{"t":"Tek iplik kırılganlığı","a":"Daha savunmasız","d":"Tek iplikli DNA, çift sarmala göre çok daha kırılgan ve kimyasal olarak savunmasızdır. Açıkta kalan bazlar zarar görebilir."},{"t":"Olası hasarlar","a":"Katlanma ve hasar","d":"Korunmayan tek iplik kendi içinde katlanabilir veya hasara uğrayabilir. Ayrıca iki iplik tekrar yanlış biçimde birleşebilir."},{"t":"Koruma yolu","a":"Bağlayıcı proteinler","d":"Tek iplik bağlayıcı proteinler açılan bölgeleri hemen kaplayarak korur. Böylece iplikler düz ve hasarsız kalır."},{"t":"Sonuç","a":"Doğru kopyalama","d":"Hızlı koruma sayesinde kalıp bozulmadan kopyalanır. Korunmazsa kalıp hasar görür ve mutasyonlar artardı."}],"ans":"Helikazın açtığı tek iplik kırılgan olduğundan bağlayıcı proteinlerle hızlı korunur; korunmazsa katlanma, hasar ve mutasyon oluşur."},{"q":"Helikaz hızı ile DNA polimeraz hızının replikasyon çatalında neden uyumlu olması gerektiğini açıklayınız.","steps":[{"t":"Helikazın hızı","a":"Kalıp üretir","d":"Helikaz sarmalı açarak DNA polimerazın okuyacağı tek iplikli kalıbı belirli bir hızla üretir. Açma hızı kalıp arzını belirler."},{"t":"Polimerazın hızı","a":"Kalıbı tüketir","d":"DNA polimeraz açılan kalıbı okuyarak yeni iplik sentezler. Sentez hızı kalıbın ne kadar hızlı tüketildiğini belirler."},{"t":"Uyum gerekliliği","a":"Açık iplik birikmesin","d":"Helikaz çok hızlı açarsa korunması gereken aşırı tek iplik birikir. Polimeraz çok hızlı olursa kalıp yetersiz kalır."},{"t":"Sonuç","a":"Eş güdümlü hız","d":"Bu nedenle iki enzimin hızı eş güdümlü olmalıdır. Uyumlu hız, fazla tek iplik birikmeden kararlı replikasyonu sağlar."}],"ans":"Helikaz kalıbı üretir, polimeraz tüketir; hızları uyumlu olmazsa ya tek iplik birikir ya kalıp yetersiz kalır, bu yüzden eş güdüm gerekir."},{"q":"Helikazın replikasyon kompleksindeki konumunun lider ve gecikmeli iplik sentezini eş zamanlı yönetmeye nasıl olanak sağladığını açıklayınız.","steps":[{"t":"Helikazın konumu","a":"Çatalın ucunda","d":"Helikaz replikasyon çatalının açılma ucunda yer alır ve iki kalıbı aynı anda açığa çıkarır. Diğer enzimler helikaza yakın çalışır."},{"t":"İki iplik sentezi","a":"Lider ve gecikmeli","d":"Açılan iki kalıptan biri sürekli lider iplik, diğeri kesikli gecikmeli iplik olarak sentezlenir. Her iki sentez de aynı çatalda yürür."},{"t":"Eş zamanlı yönetim","a":"Komplekste birleşme","d":"Helikazın ucundaki replikasyon kompleksi her iki polimerazı bir arada tutar. Gecikmeli iplik kalıbı genellikle kıvrılarak komplekse yaklaştırılır."},{"t":"Sonuç","a":"Birlikte ilerleme","d":"Böylece lider ve gecikmeli iplik sentezi helikazla birlikte eş zamanlı yürütülür. Bu, çatalın bir bütün halinde ilerlemesini sağlar."}],"ans":"Helikazın çatal ucundaki konumu, kompleksin her iki polimerazı bir arada tutmasını sağlar; böylece lider ve gecikmeli iplik sentezi eş zamanlı yürütülür."},{"q":"Helikazın replikasyon başlangıcında A-T zengini bölgeleri tercih etmesinin termodinamik nedenini açıklayınız.","steps":[{"t":"Bağ enerjisi","a":"A-T iki, G-C üç bağ","d":"Adenin-timin çifti iki, guanin-sitozin çifti üç hidrojen bağı içerir. Bağ sayısı arttıkça çiftin açılması için gereken enerji artar."},{"t":"Termodinamik fark","a":"Az enerji az bağ","d":"A-T zengini bölgeler daha az hidrojen bağı içerdiği için açılmaları daha az enerji gerektirir. Bu, açılmayı termodinamik olarak kolaylaştırır."},{"t":"Helikazın tercihi","a":"Kolay açılan bölge","d":"Helikaz, daha düşük enerjiyle açılabilen A-T zengini bölgeleri başlangıç için tercih eder. Bu, replikasyonun verimli başlamasını sağlar."},{"t":"Sonuç","a":"Verimli başlangıç","d":"Düşük enerjili açılma sayesinde başlangıç hızlı ve verimli olur. Böylece replikasyon kompleksi rahatça kurulur."}],"ans":"A-T çiftleri daha az hidrojen bağı içerip daha az enerjiyle açıldığından, helikaz termodinamik açıdan kolay olan bu bölgeleri başlangıç için tercih eder."},{"q":"Helikaz aktivitesinin hücre döngüsünde sıkı denetlenmesinin genom kararlılığı açısından önemini açıklayınız.","steps":[{"t":"Helikaz aktivitesi","a":"Replikasyonu başlatır","d":"Helikazın sarmalı açması replikasyonun başlamasını tetikler. Bu nedenle helikaz aktivitesi kopyalamanın zamanlamasını belirler."},{"t":"Denetim gerekliliği","a":"Doğru zamanda açma","d":"Helikaz yalnızca uygun hücre döngüsü evresinde aktif olmalıdır. Aksi halde DNA yanlış zamanda veya birden fazla kez kopyalanabilir."},{"t":"Kontrolsüz aktivite","a":"Aşırı kopyalama","d":"Denetlenmeyen helikaz aynı bölgenin tekrar tekrar kopyalanmasına yol açabilir. Bu, kromozom anormalliklerine ve mutasyonlara neden olur."},{"t":"Sonuç","a":"Genom kararlılığı","d":"Sıkı denetim, DNA nın döngü başına yalnızca bir kez kopyalanmasını sağlar. Bu da genom kararlılığını ve doğru hücre bölünmesini güvence altına alır."}],"ans":"Helikaz aktivitesinin döngüde sıkı denetlenmesi, DNA nın bir kez kopyalanmasını sağlayarak aşırı kopyalamayı ve genom kararsızlığını önler."},{"q":"Helikazın açtığı çatalın bir DNA hasarıyla karşılaşması durumunda replikasyonun sürdürülebilirliğini açıklayınız.","steps":[{"t":"Çatalın ilerlemesi","a":"Helikaz açar","d":"Helikaz çatalı açarak ilerletirken kalıp ipliklerde hasarlı bölgelerle karşılaşabilir. Hasar, kalıbın düzgün okunmasını engeller."},{"t":"Hasarın etkisi","a":"Çatal durabilir","d":"Hasarlı bölgeye gelen çatal durabilir veya yavaşlayabilir. Helikaz açmaya devam etse de polimeraz hasarlı kalıbı okuyamaz."},{"t":"Sürdürme mekanizması","a":"Onarım devreye girer","d":"Hücre, durmuş çatalı korumak ve hasarı onarmak için özel sistemler devreye sokar. Onarım tamamlanınca çatal yeniden ilerleyebilir."},{"t":"Sonuç","a":"Bütünlük korunur","d":"Bu mekanizmalar sayesinde replikasyon hasara rağmen tamamlanabilir. Böylece genom bütünlüğü korunmuş olur."}],"ans":"Hasara gelen çatal durabilir; hücre onarım sistemlerini devreye sokarak hasarı giderir ve helikazın açtığı çatalın replikasyonu tamamlamasını sağlar."},{"q":"Helikaz, topoizomeraz ve tek iplik bağlayıcı proteinlerin birlikte çalışmasının replikasyon çatalının kararlılığını nasıl sağladığını açıklayınız.","steps":[{"t":"Helikazın işlevi","a":"Sarmalı açar","d":"Helikaz çatalın ucunda hidrojen bağlarını koparıp iplikleri ayırır. Bu, kalıbı ortaya çıkaran temel adımdır."},{"t":"Topoizomerazın katkısı","a":"Gerginliği giderir","d":"Açılma sırasında ileri bölgede biriken süpersarımı topoizomeraz keserek giderir. Böylece helikazın ilerlemesi engellenmez."},{"t":"Bağlayıcı proteinin katkısı","a":"İplikleri korur","d":"Tek iplik bağlayıcı proteinler açılan iplikleri kaplayarak kapanmayı ve hasarı önler. Kalıp bu sayede açık ve sağlam kalır."},{"t":"Sonuç","a":"Kararlı çatal","d":"Üç bileşen birlikte çalışınca çatal hem açık hem gergin olmayan hem korunmuş durumda kalır. Bu eş güdüm çatalın kararlı ve kesintisiz ilerlemesini sağlar."}],"ans":"Helikaz açar, topoizomeraz gerginliği giderir, bağlayıcı proteinler iplikleri korur; bu üçlü eş güdüm replikasyon çatalını kararlı ve kesintisiz tutar."}]}},"polimeraz":{"ilkokul":{"kolay":[{"q":"DNA polimeraz enziminin temel görevi nedir?","steps":[{"t":"Enzimi tanıyalım","a":"DNA ile çalışan enzim","d":"DNA polimeraz, hücrede DNA kopyalanırken görev alan bir enzimdir. Adındaki polimeraz, parçaları birbirine ekleyen anlamına gelir."},{"t":"Görevini bulalım","a":"Yeni iplik yapar","d":"DNA polimeraz, açılmış DNA ipliğinin karşısına yeni bir iplik yapar. Bunu nükleotitleri sırayla ekleyerek gerçekleştirir."}],"ans":"DNA polimeraz, açılan DNA ipliğinin karşısına nükleotitleri ekleyerek yeni iplik yapar."},{"q":"DNA polimeraz yeni ipliği yaparken neyi örnek olarak kullanır?","steps":[{"t":"Örnek iplik gerekir","a":"Açık iplik vardır","d":"DNA kopyalanırken açılmış bir DNA ipliği bulunur. Bu açık iplik yeni iplik için örnek olur."},{"t":"Polimerazın kullanımı","a":"Kalıp ipliği okur","d":"DNA polimeraz bu örnek ipliği yani kalıp ipliği okur. Okuduğu sıraya göre yeni nükleotitleri ekler."}],"ans":"DNA polimeraz, açılmış kalıp ipliği örnek alarak yeni iplik yapar."},{"q":"DNA polimeraz yeni iplikte parçaları nereye ekler?","steps":[{"t":"Yeni iplik büyür","a":"Uca ekleme yapılır","d":"Yeni iplik yapılırken nükleotitler tek tek eklenir. Her yeni nükleotit ipliğin ucuna gelir."},{"t":"Polimerazın işi","a":"Sırayla ekler","d":"DNA polimeraz nükleotitleri ipliğin ucuna sırayla ekleyerek ipliği uzatır. Böylece yeni iplik adım adım büyür."}],"ans":"DNA polimeraz nükleotitleri yeni ipliğin ucuna sırayla ekleyerek ipliği uzatır."},{"q":"DNA polimeraz kalıp ipliği okumasaydı yeni iplik doğru olur muydu?","steps":[{"t":"Doğru iplik için","a":"Kalıp okunmalı","d":"Yeni ipliğin doğru olması için kalıp ipliğin sırasına uyması gerekir. Bu yüzden kalıbın okunması çok önemlidir."},{"t":"Okumadan yapılırsa","a":"Yanlış iplik olur","d":"Kalıp okunmazsa nükleotitler yanlış sırada eklenir. Bu durumda yeni iplik hatalı olur."}],"ans":"Hayır, kalıp okunmazsa nükleotitler yanlış eklenir ve yeni iplik hatalı olur."},{"q":"DNA polimeraz çalışınca DNA dan kaç tane DNA oluşur?","steps":[{"t":"Başlangıç","a":"Bir DNA vardır","d":"Kopyalama başlamadan önce hücrede bir tane DNA molekülü bulunur. Bu DNA kopyalanmaya hazırlanır."},{"t":"Polimerazdan sonra","a":"İki DNA oluşur","d":"DNA polimeraz her kalıbın karşısına yeni iplik yaptıktan sonra iki tane DNA oluşur. Bu iki DNA birbirinin aynısıdır."}],"ans":"Bir DNA dan, DNA polimerazın çalışmasıyla birbirinin aynısı iki DNA oluşur."}],"zor":[{"q":"DNA polimeraz yeni nükleotitleri hangi yönde ekler?","steps":[{"t":"İpliğin uçları","a":"İki farklı uç var","d":"DNA ipliğinin iki ucu birbirinden farklıdır; bu uçlar 5 ve üç olarak adlandırılır. Polimeraz ekleme yaparken bu uçlara dikkat eder."},{"t":"Ekleme yönü","a":"5 ten üç e doğru","d":"DNA polimeraz yeni nükleotitleri her zaman 5 ten üç e doğru ekler. Yani iplik bu yönde uzar."}],"ans":"DNA polimeraz yeni nükleotitleri her zaman 5 ten üç e (5 üç) yönünde ekler."},{"q":"DNA polimeraz işe başlamadan önce kalıba ne yerleştirilmesi gerekir?","steps":[{"t":"Polimerazın ihtiyacı","a":"Başlangıç gerekir","d":"DNA polimeraz boş bir kalıba kendi başına başlayamaz. Eklemeye devam edebilmek için bir başlangıç parçasına ihtiyaç duyar."},{"t":"Başlangıç parçası","a":"RNA primer konur","d":"Kalıba kısa bir RNA primer yerleştirilir. DNA polimeraz bu primerin ucundan başlayarak nükleotit eklemeye devam eder."}],"ans":"DNA polimerazın başlaması için kalıba önce kısa bir RNA primer yerleştirilmelidir."},{"q":"DNA polimeraz yanlış bir nükleotit eklerse ne yapabilir?","steps":[{"t":"Hata oluşabilir","a":"Yanlış eşleşme","d":"DNA polimeraz çalışırken bazen kalıba uymayan yanlış bir nükleotit ekleyebilir. Bu bir hata oluşturur."},{"t":"Düzeltme özelliği","a":"Hatayı çıkarır","d":"DNA polimeraz yanlış nükleotiti fark eder ve geri çıkarır. Sonra doğru nükleotiti ekleyerek hatayı düzeltir."}],"ans":"DNA polimeraz yanlış nükleotiti fark edip çıkarır ve yerine doğrusunu ekleyerek hatayı düzeltir."},{"q":"DNA polimerazın hataları düzeltmesi neden önemlidir?","steps":[{"t":"Hataların etkisi","a":"Yanlış bilgi oluşur","d":"Yeni iplikte kalan bir hata, DNA daki bilgiyi yanlış hale getirir. Bu yanlış bilgi yeni hücrelere de geçebilir."},{"t":"Düzeltmenin yararı","a":"Doğru kopya sağlar","d":"DNA polimeraz hataları düzelttiği için yeni DNA çok daha doğru olur. Böylece bilgi güvenli biçimde aktarılır."}],"ans":"Hataları düzeltmek, yeni DNA nın doğru olmasını ve bilginin güvenle aktarılmasını sağlar."},{"q":"DNA polimeraz kalıptaki bir bazın karşısına hangi bazı ekler?","steps":[{"t":"Bazların eşleşmesi","a":"Belirli çiftler vardır","d":"DNA da bazlar belirli kurallara göre eşleşir. Adenin timinle, guanin de sitozinle eşleşir."},{"t":"Polimerazın seçimi","a":"Uygun bazı ekler","d":"DNA polimeraz kalıptaki baza bakar ve onunla eşleşen doğru bazı ekler. Örneğin kalıpta adenin varsa karşısına timin koyar."}],"ans":"DNA polimeraz, kalıptaki baza uygun eşi ekler; adenin karşısına timin, guanin karşısına sitozin koyar."}]},"ortaokul":{"kolay":[{"q":"DNA polimeraz enzimi yeni iplikte nükleotitleri hangi yönde ekler?","steps":[{"t":"İpliğin yönü","a":"5 ve üç uçları","d":"DNA ipliğinin iki ucu farklıdır ve 5 ile üç olarak adlandırılır. Bu yönler ipliğin nasıl uzayacağını belirler."},{"t":"Ekleme yönü","a":"5 üç yönünde","d":"DNA polimeraz yeni nükleotitleri yalnızca 5 ten üç e doğru ekler. Yani yeni iplik bu yönde uzar."}],"ans":"DNA polimeraz yeni iplikteki nükleotitleri 5 üç yönünde ekler."},{"q":"DNA polimerazın başlayabilmesi için neye ihtiyacı vardır?","steps":[{"t":"Polimerazın kısıtı","a":"Sıfırdan başlayamaz","d":"DNA polimeraz boş bir kalıp üzerine kendi başına ilk nükleotiti koyamaz. Çalışmaya başlamak için hazır bir uca ihtiyaç duyar."},{"t":"Gerekli yapı","a":"RNA primer","d":"Primaz enzimi kalıba kısa bir RNA primer yerleştirir. DNA polimeraz bu primerin ucundan başlayarak ekleme yapar."}],"ans":"DNA polimerazın başlaması için kalıba yerleştirilen kısa bir RNA primere ihtiyaç vardır."},{"q":"DNA polimeraz kalıp ipliği nasıl kullanır?","steps":[{"t":"Kalıbı okuma","a":"Bazları okur","d":"DNA polimeraz kalıp ipliğin bazlarını sırayla okur. Her bazın hangi baz olduğunu belirler."},{"t":"Eş baz ekleme","a":"Uygun nükleotiti ekler","d":"Polimeraz okuduğu her baza uygun eş bazı yeni ipliğe ekler. Böylece kalıba tam uyan yeni iplik oluşur."}],"ans":"DNA polimeraz kalıp ipliğin bazlarını okuyup her birine uygun eş bazı ekleyerek yeni iplik yapar."},{"q":"DNA polimerazın okuma-düzeltme özelliği nedir?","steps":[{"t":"Hata olasılığı","a":"Yanlış baz eklenebilir","d":"DNA polimeraz çalışırken bazen kalıba uymayan yanlış bir baz ekleyebilir. Bu yeni iplikte bir hata oluşturur."},{"t":"Düzeltme","a":"Hatayı bulup çıkarır","d":"DNA polimeraz yanlış bazı fark edip geri çıkarır ve doğrusunu ekler. Bu yeteneğe okuma-düzeltme denir."}],"ans":"Okuma-düzeltme, DNA polimerazın yanlış eklenen bazı bulup çıkararak yerine doğrusunu eklemesidir."},{"q":"DNA polimerazın oluşturduğu iki DNA molekülü birbirine göre nasıldır?","steps":[{"t":"Kalıba uyum","a":"Her kalıp aynısını verir","d":"DNA polimeraz her kalıbın karşısına ona tam uyan iplik yapar. Böylece her yeni DNA orijinal DNA ya benzer."},{"t":"Sonuç","a":"Aynı iki DNA","d":"Sonuçta oluşan iki DNA molekülü birbirinin aynısıdır. Bu sayede kalıtsal bilgi değişmeden korunur."}],"ans":"DNA polimerazın oluşturduğu iki DNA molekülü birbirinin aynısıdır ve orijinal DNA ile aynı bilgiyi taşır."}],"zor":[{"q":"DNA polimeraz neden RNA primere ihtiyaç duyar ve bu primer sonradan ne olur?","steps":[{"t":"Polimerazın kısıtı","a":"Serbest uç ister","d":"DNA polimeraz yalnızca var olan bir nükleotit zincirinin serbest ucuna ekleme yapabilir. Sıfırdan ilk nükleotiti koyamaz."},{"t":"Primerin görevi","a":"Başlangıç sağlar","d":"RNA primer, polimerazın ekleme yapabileceği serbest bir uç oluşturur. Polimeraz bu ucun devamına DNA nükleotitlerini ekler."},{"t":"Primerin sonu","a":"Çıkarılıp değiştirilir","d":"İş bitince RNA primer çıkarılır ve yerine DNA nükleotitleri konur. Böylece yeni iplik tamamen DNA dan oluşur."}],"ans":"DNA polimeraz serbest uç gerektirdiğinden RNA primer başlangıç sağlar; primer sonradan çıkarılıp yerine DNA nükleotitleri konur."},{"q":"DNA polimerazın 5 üç yönünde çalışması iki kalıp ipliğin sentezini nasıl farklılaştırır?","steps":[{"t":"Yön kısıtı","a":"Sadece 5 üç","d":"DNA polimeraz nükleotitleri yalnızca 5 üç yönünde ekleyebilir. Bu kural iki kalıp için de geçerlidir."},{"t":"Kalıpların yönü","a":"İki kalıp ters","d":"Çatalda açılan iki kalıp birbirine ters yöndedir. Bu nedenle ikisi aynı şekilde sürekli kopyalanamaz."},{"t":"Sonuç","a":"Sürekli ve kesikli","d":"Bir kalıp sürekli tek parça halinde, diğeri kısa parçalar halinde kesikli sentezlenir. Böylece iki iplik farklı biçimde yapılır."}],"ans":"5 üç kısıtı nedeniyle bir kalıp sürekli, ters yöndeki diğer kalıp kısa parçalar halinde kesikli olarak sentezlenir."},{"q":"DNA polimerazın okuma-düzeltme özelliği olmasaydı kalıtsal bilgiye ne olurdu?","steps":[{"t":"Hata birikimi","a":"Hatalar kalır","d":"Okuma-düzeltme olmasaydı yanlış eklenen bazlar yeni iplikte kalırdı. Her kopyalamada yeni hatalar eklenirdi."},{"t":"Mutasyon artışı","a":"Çok mutasyon","d":"Düzeltilmeyen hatalar mutasyon olarak DNA da kalıcı hale gelir. Bu da mutasyon oranını büyük ölçüde artırır."},{"t":"Sonuç","a":"Bilgi bozulur","d":"Çok sayıda mutasyon kalıtsal bilgiyi bozar ve hücre işlevlerini aksatır. Bu durum canlı için zararlı olabilir."}],"ans":"Okuma-düzeltme olmasaydı hatalar mutasyon olarak birikir, kalıtsal bilgi bozulur ve hücre işlevleri aksardı."},{"q":"DNA polimeraz kalıptaki baz dizisine göre yeni ipliğin dizisini nasıl belirler?","steps":[{"t":"Eşleşme kuralı","a":"Belirli baz çiftleri","d":"DNA da bazlar belirli kurallarla eşleşir; adenin timinle, guanin sitozinle eşleşir. Bu kurala tamamlayıcılık denir."},{"t":"Kalıbı okuma","a":"Her bazı belirler","d":"DNA polimeraz kalıbı baz baz okuyarak hangi bazın bulunduğunu belirler. Her baz için doğru eşi seçer."},{"t":"Yeni dizi","a":"Tamamlayıcı dizi","d":"Polimeraz her kalıp bazının eşini ekleyerek tamamlayıcı bir dizi oluşturur. Böylece yeni ipliğin dizisi kalıp tarafından belirlenmiş olur."}],"ans":"DNA polimeraz kalıbı baz baz okuyup tamamlayıcılık kuralına göre eş bazları ekler; böylece yeni ipliğin dizisi kalıba göre belirlenir."},{"q":"DNA polimeraz, helikaz ve primazın replikasyon çatalında çalışma sırasını açıklayınız.","steps":[{"t":"İlk adım","a":"Helikaz açar","d":"Önce helikaz çift sarmalı açarak tek iplikli kalıpları ortaya çıkarır. Bu olmadan diğer enzimler çalışamaz."},{"t":"İkinci adım","a":"Primaz primer koyar","d":"Açılan kalıp üzerine primaz kısa bir RNA primer yerleştirir. Bu primer DNA polimerazın başlaması için gereklidir."},{"t":"Üçüncü adım","a":"Polimeraz ekler","d":"DNA polimeraz primerin ucundan başlayarak kalıbı okur ve yeni nükleotitleri 5 üç yönünde ekler. Böylece yeni iplik sentezlenir."}],"ans":"Önce helikaz sarmalı açar, sonra primaz RNA primer koyar, ardından DNA polimeraz primerden başlayarak yeni ipliği sentezler."}]},"lise":{"kolay":[{"q":"DNA polimeraz enziminin temel işlevini ve çalışma yönünü açıklayınız.","steps":[{"t":"Temel işlev","a":"Yeni iplik sentezler","d":"DNA polimeraz, kalıp iplik üzerine yeni DNA ipliği sentezleyen enzimdir. Bunu nükleotitleri sırayla birbirine bağlayarak yapar."},{"t":"Çalışma yönü","a":"5 üç yönünde","d":"Polimeraz yeni nükleotitleri yalnızca 5 üç yönünde ekler. Yani büyüyen ipliğin üç ucuna ekleme yapar."},{"t":"Kalıp kullanımı","a":"Tamamlayıcı sentez","d":"Polimeraz kalıbı okuyarak ona tamamlayıcı dizi sentezler. Böylece kalıba tam uyan yeni iplik oluşur."}],"ans":"DNA polimeraz, kalıbı okuyarak yeni nükleotitleri 5 üç yönünde ekleyip kalıba tamamlayıcı yeni iplik sentezler."},{"q":"DNA polimerazın RNA primere neden ihtiyaç duyduğunu açıklayınız.","steps":[{"t":"Polimerazın kısıtı","a":"Serbest 3 ucu ister","d":"DNA polimeraz yalnızca var olan bir zincirin serbest üç ucuna nükleotit ekleyebilir. Sıfırdan ilk nükleotiti koyamaz."},{"t":"Primerin sağladığı","a":"Başlangıç ucu","d":"Primaz enzimi kalıba kısa bir RNA primer koyar ve serbest bir üç ucu oluşturur. Polimeraz bu uçtan başlayarak ekleme yapar."},{"t":"Sonuç","a":"Sentez başlar","d":"Primer sayesinde polimerazın başlangıç ihtiyacı karşılanır ve sentez başlar. Primer sonradan çıkarılıp yerine DNA konur."}],"ans":"DNA polimeraz serbest 3 ucu gerektirdiğinden, primaz tarafından konan RNA primer başlangıç ucunu sağlar."},{"q":"DNA polimerazın kalıp ipliği nasıl okuyup tamamlayıcı iplik oluşturduğunu açıklayınız.","steps":[{"t":"Tamamlayıcılık kuralı","a":"A-T ve G-C eşleşir","d":"DNA da adenin timinle, guanin sitozinle eşleşir. Bu eşleşme tamamlayıcılık kuralı olarak bilinir."},{"t":"Kalıbı okuma","a":"Bazları sırayla okur","d":"DNA polimeraz kalıbı baz baz okuyarak her bazın kimliğini belirler. Okuma sırası yeni ipliğin dizisini yönlendirir."},{"t":"Eş baz ekleme","a":"Tamamlayıcı dizi","d":"Polimeraz her kalıp bazının eşini yeni ipliğe ekler. Böylece kalıba tamamlayıcı yeni iplik dizisi oluşur."}],"ans":"DNA polimeraz kalıbı baz baz okuyup tamamlayıcılık kuralına göre eş bazları ekleyerek kalıba tamamlayıcı yeni iplik oluşturur."},{"q":"DNA polimerazın okuma-düzeltme özelliğinin replikasyon doğruluğuna katkısını açıklayınız.","steps":[{"t":"Hata olasılığı","a":"Yanlış nükleotit","d":"DNA polimeraz hızlı çalışırken zaman zaman yanlış bir nükleotit ekleyebilir. Bu, yeni iplikte bir eşleşme hatası oluşturur."},{"t":"Düzeltme işlevi","a":"Hatayı çıkarır","d":"Polimeraz yanlış nükleotiti fark eder, geri çıkarır ve doğrusunu ekler. Bu yeteneğe okuma-düzeltme denir."},{"t":"Katkısı","a":"Doğruluğu artırır","d":"Okuma-düzeltme sayesinde hata oranı çok düşer. Böylece replikasyon yüksek doğrulukla tamamlanır."}],"ans":"DNA polimeraz yanlış nükleotiti bulup çıkararak doğrusunu ekler; bu okuma-düzeltme replikasyon doğruluğunu büyük ölçüde artırır."},{"q":"DNA polimerazın 5 üç yönünde çalışmasının lider iplik sentezine etkisini açıklayınız.","steps":[{"t":"Yön kısıtı","a":"Sadece 5 üç","d":"DNA polimeraz nükleotitleri yalnızca 5 üç yönünde ekleyebilir. Bu kural sentezin nasıl yürüyeceğini belirler."},{"t":"Lider iplik","a":"Çatalla aynı yön","d":"Açılma yönüyle uyumlu olan kalıpta polimeraz çatalı izleyerek kesintisiz ekleme yapar. Bu iplik lider iplik olarak adlandırılır."},{"t":"Sonuç","a":"Sürekli sentez","d":"Lider iplik tek bir primerle sürekli olarak sentezlenir. Bu, hızlı ve kesintisiz iplik yapımı sağlar."}],"ans":"5 üç yönü çatalın açılmasıyla uyumlu olan kalıpta polimeraz kesintisiz çalışır ve lider iplik sürekli sentezlenir."},{"q":"DNA polimerazın gecikmeli iplikte neden Okazaki parçaları oluşturduğunu açıklayınız.","steps":[{"t":"Kalıbın yönü","a":"Çatala ters","d":"Gecikmeli iplik kalıbı, çatalın açılma yönüne terstir. Bu nedenle polimeraz çatalı sürekli izleyemez."},{"t":"Parçalı sentez","a":"Geri doğru ekler","d":"Polimeraz bu kalıpta kısa parçalar halinde, çatalın gerisine doğru ekleme yapar. Her parça ayrı bir primerle başlar."},{"t":"Sonuç","a":"Okazaki parçaları","d":"Bu kısa DNA parçalarına Okazaki parçaları denir. Sonradan bu parçalar birbirine bağlanarak tam iplik oluşur."}],"ans":"Gecikmeli iplik kalıbı çatala ters olduğundan, DNA polimeraz kısa Okazaki parçaları halinde kesikli sentez yapar."},{"q":"DNA polimerazın iki yeni DNA molekülünün birbirinin aynısı olmasını nasıl sağladığını açıklayınız.","steps":[{"t":"Kalıp temelli sentez","a":"Her kalıp aynısını verir","d":"DNA polimeraz her kalıbı tamamlayıcılık kuralına göre kopyalar. Böylece her yeni iplik kalıbına tam uyar."},{"t":"Yarı korunumlu yapı","a":"Bir eski bir yeni","d":"Her yeni DNA bir eski kalıp ve bir yeni iplikten oluşur. Eski iplik bilgiyi koruyarak aktarır."},{"t":"Sonuç","a":"Özdeş moleküller","d":"Aynı kuralla kopyalandığı için iki DNA molekülü birbirinin aynısı olur. Bu, kalıtsal bilginin değişmeden aktarılmasını sağlar."}],"ans":"DNA polimeraz her kalıbı tamamlayıcılık kuralıyla kopyaladığından, oluşan iki DNA molekülü birbirinin aynısı ve orijinalle özdeştir."},{"q":"DNA polimerazın çalışması için neden açık kalıp iplik gerektiğini açıklayınız.","steps":[{"t":"Polimerazın okuması","a":"Bazları görmeli","d":"DNA polimeraz tamamlayıcı nükleotit seçmek için kalıp bazları okumalıdır. Bunun için bazların açıkta olması gerekir."},{"t":"Çift sarmal engeli","a":"Bazlar gizli","d":"Çift sarmalda bazlar içeride eşleşmiş ve gizlenmiştir. Bu yapıda polimeraz kalıbı okuyamaz."},{"t":"Sonuç","a":"Helikaz açmalı","d":"Helikaz sarmalı açıp tek iplikli kalıp oluşturduğunda bazlar erişilebilir olur. Ancak o zaman polimeraz çalışabilir."}],"ans":"DNA polimeraz kalıp bazları okumak için açık tek iplikli kalıp gerektirir; bu nedenle önce helikazın sarmalı açması şarttır."},{"q":"DNA polimerazın eklediği nükleotitlerin kalıptaki bazlarla ilişkisini açıklayınız.","steps":[{"t":"Eşleşme kuralı","a":"Belirli çiftler","d":"Adenin timinle iki, guanin sitozinle üç hidrojen bağı yaparak eşleşir. Bu eşleşme kalıp ve yeni iplik arasında geçerlidir."},{"t":"Polimerazın seçimi","a":"Uygun nükleotit","d":"DNA polimeraz kalıptaki baza bakarak ona uygun nükleotiti seçer. Yanlış eşleşen nükleotitler genellikle kabul edilmez."},{"t":"Sonuç","a":"Doğru dizi","d":"Bu seçicilik sayesinde yeni iplik kalıba tam uyan bir dizi alır. Böylece kopyalama doğru gerçekleşir."}],"ans":"DNA polimeraz, kalıptaki her baza tamamlayıcı nükleotiti seçerek (A karşısına T, G karşısına C) kalıba tam uyan dizi oluşturur."},{"q":"DNA polimerazın replikasyon hızındaki rolünü açıklayınız.","steps":[{"t":"Sentez hızı","a":"Nükleotit ekler","d":"DNA polimeraz saniyede çok sayıda nükleotit ekleyebilen hızlı bir enzimdir. Sentez hızı kopyalama süresini doğrudan etkiler."},{"t":"Sürekli çalışma","a":"Çatalla ilerler","d":"Lider iplikte polimeraz çatalla birlikte kesintisiz ilerler. Bu, kopyalamanın hızlı yürümesini sağlar."},{"t":"Sonuç","a":"Hız belirleyici","d":"Polimerazın sentez hızı, helikazın açma hızıyla birlikte replikasyon hızını belirler. Hızlı ve doğru sentez verimli kopyalama sağlar."}],"ans":"DNA polimeraz yüksek hızla nükleotit ekleyerek ve çatalla birlikte ilerleyerek replikasyon hızını belirleyen önemli bir enzimdir."},{"q":"DNA polimerazın oluşturduğu yeni iplik ile eski iplik arasındaki ilişkiyi yarı korunumlu model ile açıklayınız.","steps":[{"t":"Eski iplik","a":"Kalıp olur","d":"Replikasyonda her eski iplik kalıp olarak kullanılır ve korunur. DNA polimeraz bu kalıbı okuyarak çalışır."},{"t":"Yeni iplik","a":"Kalıba göre sentezlenir","d":"Polimeraz kalıba tamamlayıcı yeni iplik sentezler. Yeni iplik eski iplikle eşleşerek çift sarmal oluşturur."},{"t":"Yarı korunumlu sonuç","a":"Bir eski bir yeni","d":"Sonuçta her DNA molekülünde bir eski bir yeni iplik bulunur. Bu modele yarı korunumlu replikasyon denir."}],"ans":"DNA polimeraz eski ipliği kalıp alıp tamamlayıcı yeni iplik sentezler; her DNA bir eski bir yeni iplik içerir, bu yarı korunumlu modeldir."},{"q":"DNA polimerazın gecikmeli iplikte oluşturduğu Okazaki parçalarının nasıl birleştirildiğini açıklayınız.","steps":[{"t":"Parçaların oluşumu","a":"Kısa DNA parçaları","d":"Gecikmeli iplikte DNA polimeraz kısa Okazaki parçaları sentezler. Her parça ayrı bir RNA primerle başlar."},{"t":"Primerlerin değişimi","a":"RNA çıkarılır","d":"RNA primerler çıkarılır ve yerine DNA nükleotitleri konur. Böylece parçalar tamamen DNA dan oluşur."},{"t":"Birleştirme","a":"Ligaz bağlar","d":"DNA ligaz enzimi komşu parçaların uçlarını birbirine bağlar. Böylece kesikli parçalar tek bir sürekli iplik haline gelir."}],"ans":"Okazaki parçalarının RNA primerleri DNA ile değiştirilir, sonra DNA ligaz parçaların uçlarını bağlayarak sürekli bir iplik oluşturur."},{"q":"DNA polimerazın hatasız çalışmasının kalıtsal bilginin korunmasındaki önemini açıklayınız.","steps":[{"t":"Bilginin aktarımı","a":"DNA bilgi taşır","d":"DNA, canlının kalıtsal bilgisini baz dizisi olarak taşır. Bu bilgi yeni hücrelere kopyalanarak aktarılır."},{"t":"Hatasız sentez","a":"Doğru dizi","d":"DNA polimerazın doğru ve okuma-düzeltmeli çalışması yeni ipliğin hatasız olmasını sağlar. Böylece baz dizisi değişmeden korunur."},{"t":"Önemi","a":"Bilgi korunur","d":"Hatasız kopyalama, kalıtsal bilginin nesilden nesile sağlıklı aktarılmasını sağlar. Hatalar olsaydı bilgi bozulur ve hastalıklar artardı."}],"ans":"DNA polimerazın doğru ve okuma-düzeltmeli çalışması baz dizisini değiştirmeden kopyalayarak kalıtsal bilginin sağlıklı aktarımını güvence altına alır."},{"q":"DNA polimerazın primaz ile iş birliği yapmasının gerekliliğini açıklayınız.","steps":[{"t":"Polimerazın kısıtı","a":"Başlatamaz","d":"DNA polimeraz yeni bir zinciri sıfırdan başlatamaz, yalnızca var olan uca ekler. Bu nedenle bir başlangıç parçasına ihtiyaç duyar."},{"t":"Primazın görevi","a":"Primer yapar","d":"Primaz kalıba kısa RNA primer sentezleyerek serbest bir uç oluşturur. Bu uç polimerazın başlangıç noktasıdır."},{"t":"İş birliği","a":"Birlikte çalışır","d":"Primaz primeri koyar, polimeraz devamını sentezler. Bu iş birliği olmadan yeni iplik sentezi başlayamaz."}],"ans":"DNA polimeraz zinciri başlatamadığından, primaz RNA primer koyarak başlangıç sağlar; bu iş birliği olmadan sentez başlayamaz."},{"q":"DNA polimerazın açtığı kalıp ipliği yanlış okumasının önlenmesinde tamamlayıcılık kuralının rolünü açıklayınız.","steps":[{"t":"Tamamlayıcılık","a":"Belirli eşleşme","d":"Adenin yalnızca timinle, guanin yalnızca sitozinle uygun şekilde eşleşir. Bu katı kural yanlış eşleşmeleri sınırlar."},{"t":"Polimerazın seçiciliği","a":"Uyumlu nükleotit","d":"DNA polimeraz yalnızca kalıba tamamlayıcı, doğru geometride eşleşen nükleotiti kolay kabul eder. Uyumsuz nükleotitler genellikle reddedilir."},{"t":"Sonuç","a":"Doğru okuma","d":"Tamamlayıcılık kuralı sayesinde polimeraz kalıbı doğru okur ve doğru nükleotiti ekler. Bu, kopyalamanın doğruluğunu artırır."}],"ans":"Tamamlayıcılık kuralı yalnızca doğru baz çiftlerine izin verdiğinden, DNA polimeraz uyumlu nükleotiti seçerek kalıbı yanlış okumaktan kaçınır."}],"zor":[{"q":"DNA polimerazın 5 üç sentez kısıtı ile gecikmeli iplikte oluşan topolojik sorunu ve çözümünü açıklayınız.","steps":[{"t":"Yön kısıtı","a":"Sadece 5 üç","d":"DNA polimeraz nükleotitleri yalnızca 5 üç yönünde ekleyebilir. Bu kural her iki kalıp için de değiştirilemez."},{"t":"Topolojik sorun","a":"Bir kalıp ters","d":"Çatal tek yönde açılırken iki kalıp birbirine zıt yöndedir. Ters yöndeki kalıpta polimeraz çatalı sürekli izleyemez."},{"t":"Çözüm","a":"Okazaki parçaları","d":"Ters kalıp, çatalın gerisine doğru kısa Okazaki parçaları halinde sentezlenir. Her parça ayrı primerle başlar ve sonradan birleştirilir."},{"t":"Sonuç","a":"Her iki iplik tamamlanır","d":"Böylece yön kısıtına rağmen her iki kalıp da kopyalanabilir. Bu düzen sürekli ve kesikli iplik sentezini bir arada yürütür."}],"ans":"5 üç kısıtı nedeniyle ters kalıpta çatal sürekli izlenemez; sorun, gecikmeli ipliğin Okazaki parçaları halinde kesikli sentezlenip birleştirilmesiyle çözülür."},{"q":"DNA polimerazın okuma-düzeltme aktivitesinin moleküler mekanizmasını ve hata oranına etkisini açıklayınız.","steps":[{"t":"Hatanın fark edilmesi","a":"Yanlış eşleşme","d":"Yanlış eklenen nükleotit kalıpla uygun baz çifti oluşturamaz ve şekilsel bir bozulma yaratır. Polimeraz bu uyumsuzluğu algılar."},{"t":"Geri çıkarma","a":"3 üç ekzonükleaz","d":"Polimeraz yanlış nükleotiti üç üç ekzonükleaz aktivitesiyle keserek geri çıkarır. Bu, hatalı ucu uzaklaştırır."},{"t":"Yeniden ekleme","a":"Doğru nükleotit","d":"Hatalı nükleotit çıkarıldıktan sonra polimeraz doğru nükleotiti ekler ve sentezi sürdürür. Böylece hata düzeltilmiş olur."},{"t":"Hata oranına etki","a":"Çok düşer","d":"Bu mekanizma replikasyon hata oranını yüzlerce kat azaltır. Sonuçta kopyalama çok yüksek doğrulukla tamamlanır."}],"ans":"Polimeraz yanlış eşleşmeyi algılayıp 3 üç ekzonükleaz ile keser, doğrusunu ekler; bu okuma-düzeltme hata oranını yüzlerce kat düşürür."},{"q":"DNA polimerazın yüksek hızda çalışırken hem doğruluğu hem hızı nasıl dengelediğini açıklayınız.","steps":[{"t":"Hız ihtiyacı","a":"Hızlı sentez","d":"Genomun zamanında kopyalanması için polimeraz saniyede çok sayıda nükleotit eklemelidir. Bu yüksek hız gereklidir."},{"t":"Doğruluk ihtiyacı","a":"Hatasız sentez","d":"Aynı zamanda kalıtsal bilginin korunması için sentezin doğru olması gerekir. Hız doğruluğu tehlikeye atmamalıdır."},{"t":"Denge mekanizması","a":"Seçim ve düzeltme","d":"Polimeraz doğru nükleotiti seçerek hız sağlar, yanlış olduğunda da okuma-düzeltme ile geri döner. Bu iki katmanlı denetim hızı çok düşürmeden doğruluğu korur."},{"t":"Sonuç","a":"Hızlı ve doğru","d":"Böylece replikasyon hem hızlı hem yüksek doğrulukla yürür. Bu denge, genomun zamanında ve sağlıklı kopyalanmasını sağlar."}],"ans":"Polimeraz doğru nükleotiti seçerek hız kazanır, hata olduğunda okuma-düzeltmeyle düzeltir; bu iki katmanlı denetim hızı çok düşürmeden doğruluğu korur."},{"q":"DNA polimerazın primaz, ekzonükleaz ve ligaz ile birlikte gecikmeli iplik olgunlaşmasını nasıl tamamladığını açıklayınız.","steps":[{"t":"Primer ve parça sentezi","a":"Primaz ve polimeraz","d":"Primaz her Okazaki parçası için RNA primer koyar, ardından DNA polimeraz parçayı sentezler. Böylece kısa DNA parçaları oluşur."},{"t":"Primerin uzaklaştırılması","a":"Ekzonükleaz çıkarır","d":"RNA primerler ekzonükleaz aktivitesiyle çıkarılır. Oluşan boşluk DNA nükleotitleriyle doldurulur."},{"t":"Boşluğun doldurulması","a":"Polimeraz tamamlar","d":"DNA polimeraz primer yerindeki boşluğu DNA nükleotitleriyle doldurur. Ancak parçalar arasında bir çentik kalır."},{"t":"Bağlanma","a":"Ligaz birleştirir","d":"DNA ligaz kalan çentiği kapatarak komşu parçaları kovalent bağla birleştirir. Böylece gecikmeli iplik sürekli ve olgun hale gelir."}],"ans":"Primaz primer koyar, polimeraz parçaları ve primer boşluğunu sentezler, ekzonükleaz RNA primeri çıkarır, ligaz çentikleri kapatarak gecikmeli ipliği olgunlaştırır."},{"q":"DNA polimerazın RNA primer gerektirmesinin ökaryot kromozom uçlarında yarattığı uç kısalma sorununu açıklayınız.","steps":[{"t":"Primer kısıtı","a":"Uçta primer gerekir","d":"Gecikmeli iplikte en uçtaki Okazaki parçası da bir RNA primerle başlar. Bu primer kromozomun en ucuna yerleşir."},{"t":"Primerin çıkarılması","a":"Boşluk kalır","d":"En uçtaki RNA primer çıkarıldığında, onu dolduracak serbest 3 ucu bulunmadığı için boşluk doldurulamaz. Polimeraz bu son boşluğu tamamlayamaz."},{"t":"Uç kısalma","a":"Kromozom kısalır","d":"Doldurulamayan bu uç nedeniyle her replikasyonda doğrusal kromozomun ucu biraz kısalır. Buna uç kısalma sorunu denir."},{"t":"Sonuç","a":"Telomer ve telomeraz","d":"Bu sorun, uçlarda telomer adı verilen tekrar dizileri ve bazı hücrelerde telomeraz enzimiyle hafifletilir. Böylece önemli genler korunur."}],"ans":"Uçtaki RNA primer çıkarılınca dolduracak 3 ucu olmadığından kromozom her bölünmede kısalır; bu uç kısalma sorunu telomer ve telomeraz ile hafifletilir."},{"q":"DNA polimerazın hatalı nükleotidi ayırt etmesinde baz çifti geometrisinin rolünü açıklayınız.","steps":[{"t":"Doğru çift geometrisi","a":"Belirli şekil","d":"Doğru baz çiftleri (A-T, G-C) belirli ve birbirine benzer bir geometriye sahiptir. Bu geometri polimerazın aktif bölgesine tam oturur."},{"t":"Hatalı çiftin etkisi","a":"Şekil bozulur","d":"Yanlış eşleşen bir nükleotit farklı bir geometri oluşturur ve aktif bölgeye tam oturmaz. Bu şekilsel uyumsuzluk polimeraz tarafından algılanır."},{"t":"Algılama","a":"Reddetme veya düzeltme","d":"Polimeraz uyumsuz geometrideki nükleotiti ya en baştan reddeder ya da ekledikten sonra okuma-düzeltmeyle çıkarır. Böylece hata önlenir."},{"t":"Sonuç","a":"Yüksek seçicilik","d":"Baz çifti geometrisine duyarlılık polimerazın seçiciliğini artırır. Bu, replikasyon doğruluğunun temel kaynaklarından biridir."}],"ans":"Doğru baz çiftleri tek tip geometriye sahip olduğundan, uyumsuz şekildeki yanlış nükleotit aktif bölgeye oturmaz ve polimeraz tarafından reddedilir veya düzeltilir."},{"q":"DNA polimerazın lider ve gecikmeli iplikte aynı çatalda eş zamanlı çalışmasının replikasyon kompleksinde nasıl düzenlendiğini açıklayınız.","steps":[{"t":"İki kalıbın yönü","a":"Zıt yönlü","d":"Lider ve gecikmeli iplik kalıpları çatalda birbirine zıt yöndedir. Polimeraz her iki kalıbı da 5 üç yönünde sentezlemek zorundadır."},{"t":"Kompleks yapısı","a":"Polimerazlar bağlı","d":"İki polimeraz aynı replikasyon kompleksinde bir arada bulunur. Bu, her iki ipliğin eş zamanlı sentezlenmesine olanak sağlar."},{"t":"Gecikmeli kalıbın kıvrılması","a":"İlmek oluşturur","d":"Gecikmeli iplik kalıbı bir ilmek halinde kıvrılarak polimerazın çatalla aynı yönde ilerlemesine izin verir. Böylece iki polimeraz birlikte hareket eder."},{"t":"Sonuç","a":"Eş zamanlı sentez","d":"Bu düzenleme sayesinde lider sürekli, gecikmeli kesikli olarak aynı anda sentezlenir. Çatal bir bütün olarak ilerler."}],"ans":"İki polimeraz tek komplekste bulunur ve gecikmeli kalıp ilmek yaparak aynı yönde işlenir; böylece lider ve gecikmeli iplik aynı çatalda eş zamanlı sentezlenir."},{"q":"DNA polimerazın okuma-düzeltme yeteneği bozulan bir hücrede mutasyon birikiminin ve kanser riskinin nasıl arttığını açıklayınız.","steps":[{"t":"Düzeltmenin kaybı","a":"Hatalar kalır","d":"Okuma-düzeltme bozulduğunda yanlış eklenen nükleotitler çıkarılamaz. Bu hatalar yeni iplikte kalıcı olur."},{"t":"Mutasyon birikimi","a":"Hız artar","d":"Düzeltilmeyen her hata bir mutasyon olarak birikir. Replikasyon sayısı arttıkça mutasyonlar hızla çoğalır."},{"t":"Gen işlevlerine etki","a":"Kritik genler bozulur","d":"Biriken mutasyonlar hücre bölünmesini denetleyen kritik genleri bozabilir. Bu genlerin bozulması hücre denetimini zayıflatır."},{"t":"Sonuç","a":"Kanser riski","d":"Denetimi bozulan hücreler kontrolsüz çoğalabilir, bu da kanser riskini artırır. Bu nedenle okuma-düzeltme genom sağlığı için kritiktir."}],"ans":"Okuma-düzeltme bozulunca hatalar düzeltilemez, mutasyonlar hızla birikir, kritik genler bozulur ve kontrolsüz çoğalmayla kanser riski artar."},{"q":"DNA polimerazın substrat olarak deoksiribonükleotit trifosfat kullanmasının sentez için enerji sağlamasını açıklayınız.","steps":[{"t":"Substrat yapısı","a":"Üç fosfatlı nükleotit","d":"DNA polimerazın kullandığı nükleotitler üç fosfat grubu taşır. Bu fosfat grupları yüksek enerjili bağlar içerir."},{"t":"Bağ oluşumu","a":"İki fosfat ayrılır","d":"Nükleotit eklenirken iki fosfat grubu pirofosfat olarak ayrılır. Bu kopma sırasında enerji açığa çıkar."},{"t":"Enerjinin kullanımı","a":"Bağ kurulur","d":"Açığa çıkan enerji, yeni nükleotidi büyüyen zincire bağlayan kovalent bağın kurulmasını sağlar. Böylece sentez için ayrı enerji molekülü gerekmez."},{"t":"Sonuç","a":"Kendinden enerjili","d":"Substratın yapısı sentezin enerjisini kendi içinde taşır. Pirofosfatın sonradan parçalanması da tepkimeyi ileri yönde kararlı kılar."}],"ans":"Üç fosfatlı nükleotitlerden iki fosfat pirofosfat olarak ayrılırken açığa çıkan enerji, yeni bağı kurar; böylece sentez kendi enerjisini substrattan sağlar."},{"q":"DNA polimeraz, helikaz ve primazın hız ve zamanlama açısından eş güdümlü çalışmasının replikasyon doğruluğuna ve sürekliliğine katkısını açıklayınız.","steps":[{"t":"Helikazın açması","a":"Kalıp üretir","d":"Helikaz sarmalı belirli bir hızla açarak tek iplikli kalıp üretir. Açma hızı kalıbın ne kadar hızlı hazır olduğunu belirler."},{"t":"Primazın başlatması","a":"Primer koyar","d":"Primaz açılan kalıba zamanında RNA primer koyar. Bu primerler polimerazın başlaması için doğru anda hazır olmalıdır."},{"t":"Polimerazın sentezi","a":"Kalıbı işler","d":"DNA polimeraz primerden başlayarak kalıbı yüksek doğrulukla sentezler. Polimerazın hızı helikazın açma hızıyla uyumlu olmalıdır."},{"t":"Eş güdümün sonucu","a":"Kararlı ve doğru","d":"Üç enzimin hız ve zamanlaması uyumlu olduğunda fazla tek iplik birikmez ve sentez kesintisiz yürür. Bu eş güdüm hem sürekliliği hem doğruluğu güvence altına alır."}],"ans":"Helikaz kalıbı üretir, primaz zamanında primer koyar, polimeraz uyumlu hızla sentezler; bu eş güdüm fazla tek iplik birikmesini önleyerek doğru ve kesintisiz replikasyon sağlar."},{"q":"DNA polimerazın gecikmeli iplikte birden çok primer kullanmasının primerlerin sonradan tamamen DNA ile değiştirilmesini neden gerektirdiğini açıklayınız.","steps":[{"t":"Çok primer kullanımı","a":"Her parçaya bir primer","d":"Gecikmeli iplikte her Okazaki parçası ayrı bir RNA primerle başlar. Bu nedenle iplik boyunca çok sayıda RNA primer bulunur."},{"t":"RNA nın sorunu","a":"DNA olmalı","d":"Olgun DNA ipliği tamamen deoksiribonükleotitten oluşmalıdır. RNA primerlerin iplikte kalması yapıyı kararsız ve hatalı kılar."},{"t":"Değiştirme","a":"DNA ile doldurma","d":"RNA primerler çıkarılır ve yerine DNA polimeraz tarafından DNA nükleotitleri konur. Böylece her primer bölgesi DNA ya dönüştürülür."},{"t":"Sonuç","a":"Tek tip iplik","d":"Tüm primerler DNA ile değiştirildikten sonra ligaz parçaları birleştirir ve tamamen DNA dan oluşan sürekli iplik elde edilir. Bu, ipliğin kararlı ve doğru olmasını sağlar."}],"ans":"Her Okazaki parçası RNA primerle başladığından iplikte çok sayıda RNA bulunur; olgun iplik tamamen DNA olmalı, bu yüzden primerler DNA ile değiştirilip ligazla birleştirilir."},{"q":"DNA polimerazın kalıbı sadık biçimde kopyalamasının yarı korunumlu modelin deneysel doğrulanmasıyla ilişkisini açıklayınız.","steps":[{"t":"Sadık kopyalama","a":"Tamamlayıcı sentez","d":"DNA polimeraz her eski ipliği tamamlayıcılık kuralıyla sadık biçimde kopyalar. Böylece her yeni DNA bir eski bir yeni iplik içerir."},{"t":"Yarı korunumlu öngörü","a":"Karışık molekül","d":"Yarı korunumlu model, ilk kopyalamada her DNA nın bir eski bir yeni iplikten oluşacağını öngörür. Bu, ağırlık veya yoğunluk farkıyla ayırt edilebilir."},{"t":"Deneysel ayırma","a":"Yoğunluk farkı","d":"İşaretli azot kullanılan deneylerde eski ve yeni iplikler farklı yoğunlukta olur. İlk kopyalamada tüm moleküllerin ara yoğunlukta çıkması yarı korunumu doğrular."},{"t":"Sonuç","a":"Model doğrulanır","d":"Polimerazın her ipliği ayrı kalıp alıp sadık kopyalaması, deneyde gözlenen ara yoğunluklu molekülleri açıklar. Böylece yarı korunumlu model deneysel olarak doğrulanır."}],"ans":"Polimerazın her eski ipliği sadık kopyalaması, ilk kuşakta tüm DNA ların bir eski bir yeni iplik içermesini sağlar; bu ara yoğunluklu moleküller yarı korunumlu modeli deneysel olarak doğrular."},{"q":"DNA polimerazın okuma-düzeltme dışında hücredeki onarım sistemleriyle birlikte replikasyon doğruluğunu çok katmanlı biçimde sağladığını açıklayınız.","steps":[{"t":"Birinci katman","a":"Nükleotit seçimi","d":"DNA polimeraz önce kalıba tamamlayıcı doğru nükleotidi seçerek hataları büyük ölçüde önler. Bu, doğruluğun ilk katmanıdır."},{"t":"İkinci katman","a":"Okuma-düzeltme","d":"Yanlış eklenen nükleotit, polimerazın okuma-düzeltme aktivitesiyle hemen çıkarılır. Bu, sentez sırasında çalışan ikinci katmandır."},{"t":"Üçüncü katman","a":"Eşleşme onarımı","d":"Sentezden sonra kaçan hatalar, hücrenin eşleşme onarım sistemi tarafından bulunup düzeltilir. Bu sistem yanlış eşleşen bölgeyi keser ve yeniden sentezler."},{"t":"Sonuç","a":"Çok düşük hata","d":"Bu üç katman birlikte çalışınca toplam hata oranı son derece düşer. Böylece genom çok yüksek doğrulukla kopyalanır ve korunur."}],"ans":"Doğru nükleotit seçimi, polimerazın okuma-düzeltmesi ve sentez sonrası eşleşme onarımı birlikte çalışarak hatayı çok katmanlı biçimde azaltır ve yüksek replikasyon doğruluğu sağlar."},{"q":"DNA polimerazın yalnızca 5 üç yönünde çalışabilmesinin evrimsel ve okuma-düzeltme açısından olası avantajını açıklayınız.","steps":[{"t":"Yön kısıtı","a":"5 üç ekleme","d":"DNA polimeraz yeni nükleotidi büyüyen zincirin 3 ucuna ekler. Bu nedenle sentez yalnızca 5 üç yönünde ilerler."},{"t":"Enerji kaynağı","a":"Büyüyen ucun enerjisi","d":"5 üç sentezde eklenen her yeni nükleotidin trifosfatı enerji sağlar. Eğer ters yönde sentez olsaydı, düzeltme sırasında çıkarılan uç enerji kaynağını kaybeder ve sentez duraklardı."},{"t":"Okuma-düzeltme avantajı","a":"Güvenli düzeltme","d":"5 üç yönde, yanlış uç çıkarıldığında büyüyen zincir hâlâ enerjili trifosfatlı nükleotit ekleyebilir. Bu, hatayı çıkarıp doğrusunu eklemenin enerjik olarak sorunsuz olmasını sağlar."},{"t":"Sonuç","a":"Tutarlı doğruluk","d":"Böylece 5 üç kısıtı okuma-düzeltmeyi enerjik açıdan uyumlu kılar. Bu, yüksek doğruluğun korunmasına evrimsel bir avantaj sağlar."}],"ans":"5 üç sentezde enerji eklenen yeni nükleotidin trifosfatından gelir; bu yön, yanlış uç çıkarıldığında sentezin enerjik olarak sürmesini sağlayarak okuma-düzeltmeyi uyumlu ve güvenli kılar."},{"q":"DNA polimerazın replikasyon çatalında karşılaştığı hasarlı kalıbı işleyememesi durumunda devreye giren çözüm yollarını açıklayınız.","steps":[{"t":"Hasarla karşılaşma","a":"Kalıp okunamaz","d":"DNA polimeraz kalıpta bir hasarlı bölgeye geldiğinde doğru nükleotidi seçemez. Bu durumda yüksek doğruluklu polimeraz sentezi durdurur."},{"t":"Çatalın durması","a":"Replikasyon takılır","d":"Polimerazın durması replikasyon çatalını duraklatır. Bu duraklama bir tehlike sinyali oluşturur ve hücreyi uyarır."},{"t":"Alternatif yol","a":"Onarım veya atlama","d":"Hücre ya hasarı onarım sistemleriyle düzeltir ya da hasarı geçici olarak atlayabilen özel polimerazları devreye sokar. Bu özel polimerazlar hasarın üzerinden sentez yapabilir."},{"t":"Sonuç","a":"Replikasyon sürer","d":"Hasar onarıldığında veya atlandığında yüksek doğruluklu polimeraz yeniden devralır ve sentezi sürdürür. Böylece replikasyon hasara rağmen tamamlanabilir."}],"ans":"Hasarlı kalıpta yüksek doğruluklu polimeraz durur ve çatal duraklar; hücre hasarı onarır ya da özel polimerazlarla atlatır, sonra normal polimeraz devralarak replikasyonu tamamlar."}]}},"replikasyonCatali":{"ilkokul":{"kolay":[{"q":"DNA kendini eşlerken iki ipliğin ayrıldığı, Y harfine benzeyen bölgeye ne ad verilir?","steps":[{"t":"İplikler ayrılır","a":"İki iplik açılır","d":"DNA eşlenmeye başlarken birbirine sarılı iki iplik birbirinden ayrılır. Ayrılan bu bölge tıpkı çatallaşmış bir yola benzer. Bu yüzden buraya özel bir isim verilir."},{"t":"Şekli Y harfine benzer","a":"Çatal görünümü oluşur","d":"Ayrılan iplikler önde birleşik, arkada açık olduğu için Y harfine benzer bir görüntü oluşturur. Bu açılan bölgeye replikasyon çatalı denir."}],"ans":"Replikasyon çatalı"},{"q":"DNA ipliklerini açıp ayıran enzimin adı nedir?","steps":[{"t":"İplikleri tutan bağlar","a":"İki iplik bağlarla tutulur","d":"DNA'nın iki ipliği zayıf bağlarla birbirine tutunur. Eşlenme için bu bağların çözülmesi gerekir."},{"t":"Açan enzim","a":"Özel bir enzim açar","d":"Helikaz adlı enzim bu bağları çözerek iki ipliği birbirinden ayırır. Böylece eşlenme için yer açılır."}],"ans":"Helikaz"},{"q":"DNA eşlenirken her yeni iplik hangi eski yapıyı kalıp olarak kullanır?","steps":[{"t":"Eski iplik kalıp olur","a":"Eski iplik örnek alınır","d":"DNA eşlenirken eski ipliklerin her biri bir örnek gibi kullanılır. Yeni iplikler bu örneğe bakılarak yapılır."},{"t":"Kalıp eski ipliktir","a":"Kalıp eski DNA ipliğidir","d":"Yeni iplikler eski ipliğin karşısına diziler. Yani kalıp olarak eski DNA ipliği kullanılır."}],"ans":"Eski DNA ipliği (kalıp iplik)"},{"q":"DNA eşlenmesinde yeni iplikleri kuran enzimin genel adı nedir?","steps":[{"t":"Yeni iplik kurulur","a":"Yeni iplik yapımı","d":"İki iplik ayrıldıktan sonra karşılarına yeni iplikler kurulmaya başlar. Bu işi yapan özel bir enzim vardır."},{"t":"Kuran enzim","a":"DNA polimeraz kurar","d":"DNA polimeraz adlı enzim yeni iplikleri tek tek nükleotid ekleyerek kurar. Bu enzim olmadan yeni iplik yapılamaz."}],"ans":"DNA polimeraz"},{"q":"Replikasyon çatalında kaç tane DNA ipliği açılır?","steps":[{"t":"DNA iki ipliklidir","a":"DNA'da iki iplik vardır","d":"DNA molekülü birbirine sarılı iki iplikten oluşur. Eşlenmede bu iplikler dikkate alınır."},{"t":"İki iplik açılır","a":"İki iplik ayrılır","d":"Replikasyon çatalında DNA'nın iki ipliği birbirinden ayrılır. Yani açılan iplik sayısı ikidir."}],"ans":"İki iplik"}],"zor":[{"q":"Helikaz iplikleri ayırdıktan sonra eşlenmenin devam edebilmesi için sırada hangi olay gerçekleşir?","steps":[{"t":"İplikler ayrıldı","a":"İki iplik açık duruyor","d":"Helikaz iki ipliği ayırdı ve replikasyon çatalı oluştu. Şimdi açık iplikler kalıp olarak hazır bekler."},{"t":"Yeni iplik başlar","a":"Yeni nükleotidler eklenir","d":"DNA polimeraz açılan ipliklerin karşısına uygun nükleotidleri eklemeye başlar. Böylece yeni iplikler kurulmaya başlar."}],"ans":"DNA polimeraz yeni iplikleri kurmaya başlar"},{"q":"Bir DNA molekülü eşlendiğinde sonuçta kaç tane DNA molekülü oluşur?","steps":[{"t":"Tek molekülle başlanır","a":"Başta bir DNA vardır","d":"Eşlenmenin başında ortada tek bir DNA molekülü bulunur. Bu molekül kopyalanmak üzere açılır."},{"t":"İki molekül oluşur","a":"İki yeni DNA çıkar","d":"Her eski iplik bir yeni iplikle eşleşince ortaya iki ayrı DNA molekülü çıkar. Yani bir DNA'dan iki DNA oluşur."}],"ans":"İki DNA molekülü"},{"q":"Yeni oluşan her DNA molekülünde biri eski biri yeni iki iplik bulunmasının sebebi nedir?","steps":[{"t":"Eski iplik korunur","a":"Eski iplik atılmaz","d":"Eşlenmede eski iplikler ayrılır ama yok edilmez. Her eski iplik yeni DNA'nın bir parçası olarak kalır."},{"t":"Yeni iplik eklenir","a":"Karşıya yeni iplik kurulur","d":"Eski ipliğin karşısına yeni bir iplik kurulur. Böylece her DNA'da bir eski bir yeni iplik bulunur."}],"ans":"Eski iplikler korunup yanlarına yeni iplik kurulduğu için"},{"q":"DNA eşlenmesinin canlı için neden gerekli olduğunu açıklayan en temel sebep nedir?","steps":[{"t":"Hücreler bölünür","a":"Hücre çoğalır","d":"Canlılar büyürken ve yıpranan hücreleri yenilerken hücreler bölünür. Bölünen her hücrenin DNA'ya ihtiyacı vardır."},{"t":"Her hücreye DNA gerekir","a":"DNA kopyalanmalı","d":"Bölünmeden önce DNA eşlenir ki her yeni hücre tam bir kopya alabilsin. Bu yüzden eşlenme şarttır."}],"ans":"Hücre bölünmesinde her yeni hücreye tam DNA kopyası gerektiği için"},{"q":"Replikasyon çatalında helikaz ve DNA polimeraz birlikte nasıl bir sıra ile çalışır?","steps":[{"t":"Önce açma","a":"Helikaz öne geçer","d":"İlk olarak helikaz iplikleri açar ve çatalı oluşturur. Açılan iplikler kalıp hâline gelir."},{"t":"Sonra kurma","a":"Polimeraz arkadan gelir","d":"Helikaz açtıkça DNA polimeraz hemen arkasından yeni iplikleri kurar. Böylece açma ve kurma birlikte ilerler."}],"ans":"Önce helikaz açar, hemen ardından DNA polimeraz yeni iplik kurar"}]},"ortaokul":{"kolay":[{"q":"Replikasyon çatalında 5'→3' yönünde kesintisiz olarak sentezlenen ipliğe ne ad verilir?","steps":[{"t":"İki iplik zıt yönlüdür","a":"İplikler antiparalel","d":"DNA'nın iki ipliği birbirine ters yöndedir. Bu yüzden çatalda her iplik farklı şekilde kopyalanır."},{"t":"Sürekli sentezlenen iplik","a":"Kesintisiz iplik oluşur","d":"Çatalın açılma yönüyle aynı doğrultuda olan iplik durmadan, tek parça hâlinde sentezlenir. Bu ipliğe öncül (kesintisiz) iplik denir."}],"ans":"Öncül (kesintisiz) iplik"},{"q":"Kesintili iplikte oluşan kısa DNA parçalarına ne ad verilir?","steps":[{"t":"İplik parça parça yapılır","a":"Kısa parçalar oluşur","d":"Kesintili iplik çatalın açılma yönünün tersine gittiği için tek seferde yapılamaz. Bu yüzden kısa parçalar hâlinde sentezlenir."},{"t":"Parçaların adı","a":"Okazaki parçaları","d":"Bu kısa DNA parçalarına Okazaki parçaları denir. Daha sonra birbirine bağlanırlar."}],"ans":"Okazaki parçaları"},{"q":"Okazaki parçalarını birbirine bağlayan enzimin adı nedir?","steps":[{"t":"Parçalar arasında boşluk var","a":"Parçalar ayrı durur","d":"Kesintili iplikte oluşan Okazaki parçaları başta birbirinden ayrıdır. Aralarında bağlanmamış noktalar bulunur."},{"t":"Bağlayan enzim","a":"DNA ligaz birleştirir","d":"DNA ligaz enzimi bu parçaların uçlarını birbirine bağlar. Böylece kesintili iplik tek bir bütün hâline gelir."}],"ans":"DNA ligaz"},{"q":"DNA polimerazın yeni iplik kurmaya başlaması için önce hangi kısa yapının hazırlanması gerekir?","steps":[{"t":"Polimeraz tek başına başlayamaz","a":"Başlangıç noktası gerekir","d":"DNA polimeraz sıfırdan iplik başlatamaz, var olan bir uca ekleme yapar. Bu yüzden bir başlangıç parçasına ihtiyaç vardır."},{"t":"RNA primer hazırlanır","a":"Kısa RNA başlatır","d":"Primaz enzimi kısa bir RNA primeri yapar. DNA polimeraz bu primerin ucundan devam ederek iplik kurar."}],"ans":"RNA primer (başlatıcı)"},{"q":"RNA primerini sentezleyen enzimin adı nedir?","steps":[{"t":"Primer bir RNA parçasıdır","a":"Başlatıcı RNA gerekir","d":"Eşlenmenin başlaması için kısa bir RNA primerine ihtiyaç vardır. Bu primer başlangıç noktası sağlar."},{"t":"Primazı yapar","a":"Primaz sentezler","d":"Primaz adlı enzim bu RNA primerini sentezler. Böylece DNA polimeraz çalışmaya başlayabilir."}],"ans":"Primaz"}],"zor":[{"q":"İki ipliğin zıt yönde sentezlenmesinin temel nedeni nedir?","steps":[{"t":"İplikler antiparalel","a":"İplikler ters yönlüdür","d":"DNA'nın iki ipliği birbirine zıt yönde uzanır, yani antiparaleldir. Birinin ucu 5' iken karşısındaki 3'tür."},{"t":"Polimeraz tek yönde çalışır","a":"Yalnızca 5'→3' kurar","d":"DNA polimeraz yalnızca 5'→3' yönünde nükleotid ekleyebilir. İplikler ters olduğu için biri sürekli, diğeri parçalı sentezlenir."},{"t":"Sonuç","a":"Öncül ve kesintili iplik","d":"Bu yüzden bir iplik kesintisiz (öncül), diğeri Okazaki parçaları hâlinde (kesintili) yapılır. İki iplik zıt yönde ilerler."}],"ans":"İplikler antiparalel olduğu ve polimeraz sadece 5'→3' yönünde çalıştığı için"},{"q":"Bir replikasyon çatalında öncül iplik kesintisiz, kesintili iplik parçalı sentezlenirken hangi enzimler sırayla görev alır?","steps":[{"t":"Başlatma","a":"Primaz primer kurar","d":"Önce primaz kısa RNA primerlerini sentezler. Bu primerler sentezin başlangıç noktalarını sağlar."},{"t":"Uzatma","a":"Polimeraz iplik kurar","d":"DNA polimeraz primerin ucundan başlayarak yeni iplikleri uzatır. Öncül iplikte tek parça, kesintili iplikte parçalar hâlinde çalışır."},{"t":"Birleştirme","a":"Ligaz parçaları bağlar","d":"Son olarak DNA ligaz Okazaki parçalarını birbirine bağlar. Böylece kesintili iplik bütünleşir."}],"ans":"Primaz, DNA polimeraz ve DNA ligaz"},{"q":"Helikazın çatalı sürekli açması, DNA eşlenmesinin hızını nasıl etkiler?","steps":[{"t":"Açılan iplik kalıp olur","a":"Açıldıkça kalıp artar","d":"Helikaz iplikleri açtıkça yeni kalıp bölgeler ortaya çıkar. Polimeraz ancak açılmış bölgelerde çalışabilir."},{"t":"Açma ve kurma eşgüdümlü","a":"Hız açmaya bağlı","d":"Helikaz ne kadar düzenli açarsa polimeraz da o kadar kesintisiz kurar. Açılma durursa sentez de durur."}],"ans":"Helikaz açtıkça kalıp sağlanır, açma hızı sentez hızını belirler"},{"q":"Kesintili iplikte oluşan RNA primerlerinin sonradan ne olması beklenir?","steps":[{"t":"Primer geçicidir","a":"Primer RNA'dan yapılır","d":"Kesintili iplikteki her Okazaki parçası bir RNA primeri ile başlar. Bu primerler DNA değil RNA olduğu için kalıcı değildir."},{"t":"Primer çıkarılır","a":"Yerine DNA gelir","d":"RNA primerleri sonradan çıkarılıp yerleri DNA nükleotidleriyle doldurulur. Ardından DNA ligaz boşlukları kapatır."}],"ans":"RNA primerleri çıkarılır, yerine DNA gelir ve ligaz bağlar"},{"q":"Replikasyon yarı korunumlu (semikonservatif) olarak adlandırılırsa bu ne anlama gelir?","steps":[{"t":"Eski iplik korunur","a":"Bir iplik eskidir","d":"Eşlenmede her yeni DNA molekülünde eski ipliklerden biri korunur. Yani eski bilgi kaybolmaz."},{"t":"Yeni iplik eklenir","a":"Bir iplik yenidir","d":"Korunan eski ipliğin karşısına yeni bir iplik sentezlenir. Böylece her DNA yarı eski yarı yeni olur, bu nedenle yarı korunumlu denir."}],"ans":"Her yeni DNA'da bir eski bir yeni iplik bulunması"}]},"lise":{"kolay":[{"q":"Replikasyon çatalının oluşumunda helikazın görevi nedir?","steps":[{"t":"Çift sarmal bağları","a":"Bazlar arası H bağları","d":"DNA'nın iki ipliği bazlar arasındaki hidrojen bağlarıyla bir arada durur. Eşlenme için bu bağların açılması gerekir."},{"t":"Helikaz bağları açar","a":"Hidrojen bağları çözülür","d":"Helikaz enzimi hidrojen bağlarını çözerek iki ipliği ayırır. Bu sayede Y şeklindeki replikasyon çatalı oluşur."}],"ans":"Çift sarmalı açarak replikasyon çatalını oluşturmak"},{"q":"Öncül (kesintisiz) ipliğin tek bir RNA primeri ile başlamasının nedeni nedir?","steps":[{"t":"Yönü çatalla aynı","a":"Açılma yönünde uzar","d":"Öncül iplik, çatalın açılma yönüyle aynı doğrultuda 5'→3' yönünde uzar. Bu nedenle açıldıkça kesintisiz devam edebilir."},{"t":"Tek başlangıç yeter","a":"Bir primer yeterlidir","d":"Sürekli uzayabildiği için yalnızca bir kez başlatılması yeterlidir. Bu yüzden tek bir RNA primeri ile başlar."}],"ans":"Çatal açıldıkça kesintisiz uzadığı için tek primer yeterli olur"},{"q":"Primaz enziminin replikasyondaki rolü nedir?","steps":[{"t":"Polimeraz başlatamaz","a":"Serbest 3'-OH gerekir","d":"DNA polimeraz yeni bir ipliği sıfırdan başlatamaz; eklemek için serbest bir 3'-OH ucuna ihtiyaç duyar. Bu yüzden bir başlatıcıya gereksinim vardır."},{"t":"Primaz primer yapar","a":"Kısa RNA primeri kurar","d":"Primaz kısa bir RNA primeri sentezleyerek bu serbest 3' ucu sağlar. DNA polimeraz primerin ucundan devam eder."}],"ans":"DNA polimerazın başlaması için RNA primeri sentezlemek"},{"q":"Kesintili iplikte neden birden çok RNA primeri gerekir?","steps":[{"t":"Parçalı sentez","a":"Okazaki parçaları kurulur","d":"Kesintili iplik çatalın açılma yönünün tersine sentezlendiği için kısa parçalar hâlinde yapılır. Bu parçalara Okazaki parçaları denir."},{"t":"Her parça primer ister","a":"Her parçaya bir primer","d":"Her Okazaki parçasının başlaması için ayrı bir RNA primeri gerekir. Bu yüzden kesintili iplikte çok sayıda primer bulunur."}],"ans":"Her Okazaki parçası ayrı bir primer ile başladığı için"},{"q":"DNA ligaz enziminin replikasyondaki görevi nedir?","steps":[{"t":"Parçalar arasında çentik","a":"Şeker-fosfat boşluğu","d":"Okazaki parçaları birleştikten sonra aralarında şeker-fosfat omurgasında çentik (boşluk) kalır. Bu boşlukların kapatılması gerekir."},{"t":"Ligaz bağ kurar","a":"Fosfodiester bağı yapar","d":"DNA ligaz komşu parçalar arasında fosfodiester bağı kurarak çentikleri kapatır. Böylece iplik sürekli hâle gelir."}],"ans":"Okazaki parçaları arasındaki çentikleri fosfodiester bağıyla kapatmak"},{"q":"İki ipliğin antiparalel olması ne demektir?","steps":[{"t":"Uçların yönü","a":"5' ve 3' uçları","d":"Her DNA ipliğinin bir 5' bir de 3' ucu vardır. Bu uçlar ipliğin yönünü belirler."},{"t":"Ters yönlülük","a":"İplikler zıt yönde","d":"İki iplik birbirine ters yönde uzanır; biri 5'→3' giderken karşısı 3'→5' yönündedir. Bu zıt yönlü dizilime antiparalel denir."}],"ans":"İki ipliğin birbirine zıt yönde (5'→3' ve 3'→5') uzanması"},{"q":"Öncül ve kesintili ipliklerin aynı çatalda farklı sentezlenmesinin nedeni nedir?","steps":[{"t":"Tek yönlü enzim","a":"Polimeraz 5'→3' kurar","d":"DNA polimeraz nükleotidleri yalnızca 5'→3' yönünde ekleyebilir. Bu kuraldan sapamaz."},{"t":"Ters kalıplar","a":"Kalıplar antiparalel","d":"İki kalıp iplik antiparalel olduğu için biri açılma yönünde, diğeri tersinde uzanır. Bu yüzden biri kesintisiz, diğeri parçalı sentezlenir."}],"ans":"Polimerazın tek yönlü çalışması ve kalıpların antiparalel olması"},{"q":"Replikasyonun yarı korunumlu olduğu hangi gözlemle açıklanır?","steps":[{"t":"Eski iplik kalır","a":"Bir iplik kalıptır","d":"Her yeni DNA molekülünde eski ipliklerden biri kalıp olarak korunur. Eski bilgi yeni moleküle taşınır."},{"t":"Yeni iplik eklenir","a":"Bir iplik yenidir","d":"Korunan eski ipliğin karşısına yeni iplik sentezlenir. Böylece her DNA bir eski bir yeni iplik içerir."}],"ans":"Her yeni DNA'nın bir eski bir yeni iplikten oluşması"},{"q":"Replikasyon çatalında topoizomeraz benzeri bir gevşetmenin gerekmesinin sebebi nedir?","steps":[{"t":"Helikaz açar","a":"İplikler ayrılır","d":"Helikaz çatalı açarken sarmalın önündeki bölgede aşırı burulma (gerilim) birikir. Bu burulma açmayı zorlaştırır."},{"t":"Gerilim giderilir","a":"Burulma çözülür","d":"Topoizomeraz enzimleri bu burulmayı geçici kesik ve onarımla gevşetir. Böylece çatal rahatça ilerleyebilir."}],"ans":"Helikazın önünde biriken sarmal burulmasını gidermek için"},{"q":"DNA polimerazın yeni ipliği daima serbest 3'-OH ucuna eklemesi neyi belirler?","steps":[{"t":"Ekleme noktası","a":"3'-OH ucu gerekir","d":"Yeni nükleotid, var olan ipliğin serbest 3'-OH ucuna bağlanır. Bu uç olmadan ekleme yapılamaz."},{"t":"Yön belirlenir","a":"5'→3' yönü oluşur","d":"Eklemeler hep 3' uca yapıldığı için iplik 5'→3' yönünde uzar. Bu da sentez yönünü tek yöne sabitler."}],"ans":"Sentezin yalnızca 5'→3' yönünde gerçekleşmesini"},{"q":"Replikasyon çatalında SSB (tek iplik bağlayıcı) proteinlere benzer bir desteğin işlevi nedir?","steps":[{"t":"Açık iplik kararsız","a":"Tek iplikler birleşebilir","d":"Helikaz açtıktan sonra tek iplikler tekrar birbirine yapışmaya eğilimlidir. Bu da sentezi engeller."},{"t":"İplikleri açık tutar","a":"Yeniden kapanmayı önler","d":"Tek iplik bağlayıcı proteinler açılan iplikleri kaplayarak açık tutar. Böylece kalıplar polimeraz için erişilebilir kalır."}],"ans":"Açılan tek iplikleri kararlı ve açık tutarak yeniden kapanmayı önlemek"},{"q":"Bir replikasyon çatalında sentez hangi genel sıra ile ilerler?","steps":[{"t":"Açma","a":"Helikaz çatalı açar","d":"İlk adımda helikaz çift sarmalı açarak replikasyon çatalını oluşturur. Tek iplikler kalıp hâline gelir."},{"t":"Başlatma","a":"Primaz primer kurar","d":"Primaz öncül iplikte bir, kesintili iplikte her parça için RNA primeri sentezler. Polimeraz için başlangıç hazırlanır."},{"t":"Uzatma ve birleştirme","a":"Polimeraz ve ligaz","d":"DNA polimeraz iplikleri uzatır, ardından DNA ligaz Okazaki parçalarını bağlar. Böylece iki yeni iplik tamamlanır."}],"ans":"Açma (helikaz), başlatma (primaz), uzatma (polimeraz), birleştirme (ligaz)"},{"q":"Öncül iplikte sentezin çatalla aynı yönde ilerlemesi neyi sağlar?","steps":[{"t":"Aynı yön","a":"Çatalı izler","d":"Öncül iplik, çatalın açılma yönüyle aynı doğrultuda uzar. Bu yüzden polimeraz çatalı takip ederek ilerleyebilir."},{"t":"Kesintisiz sentez","a":"Tek parça oluşur","d":"Çatalı izleyebildiği için sentez durmadan devam eder. Sonuçta öncül iplik tek bir kesintisiz parça olarak sentezlenir."}],"ans":"Sentezin kesintisiz tek parça olarak ilerlemesini"},{"q":"Kesintili iplikte polimerazın çataldan uzaklaşacak yönde çalışmasının sonucu nedir?","steps":[{"t":"Ters yön","a":"Çatalın tersine uzar","d":"Kesintili ipliğin kalıbı antiparalel olduğu için polimeraz çatalın açılma yönünün tersine doğru sentez yapar. Bu da sürekli ilerlemeyi engeller."},{"t":"Parçalı sentez","a":"Okazaki parçaları","d":"Çatal her açıldığında polimeraz yeniden geri dönüp kısa parçalar sentezler. Bu parçalara Okazaki parçaları denir."}],"ans":"İpliğin Okazaki parçaları hâlinde parçalı sentezlenmesi"},{"q":"Replikasyonun hatasız olmasının canlı için önemi nedir?","steps":[{"t":"DNA bilgi taşır","a":"Genetik bilgi korunmalı","d":"DNA, proteinlerin yapımını yöneten genetik bilgiyi taşır. Bu bilgi hücreden hücreye doğru aktarılmalıdır."},{"t":"Hatalar zararlı olabilir","a":"Mutasyon riski","d":"Eşlenmede oluşan hatalar mutasyonlara yol açabilir. Bu yüzden replikasyon yüksek doğrulukla gerçekleşmelidir."}],"ans":"Genetik bilginin sonraki hücrelere doğru aktarılmasını sağlamak"}],"zor":[{"q":"Antiparalel iplikler ve polimerazın 5'→3' kısıtı bir arada nasıl olup da hem öncül hem kesintili ipliği aynı çatalda mümkün kılar?","steps":[{"t":"Kalıp yönleri ters","a":"İki kalıp antiparalel","d":"Çatalda iki kalıp iplik zıt yönde uzanır. Biri 3'→5' okunurken karşısı 5'→3' yönündedir."},{"t":"Polimeraz tek yönlü","a":"Yalnız 5'→3' kurar","d":"Polimeraz her iki kalıpta da yeni ipliği 5'→3' yönünde sentezler. Bu nedenle kalıba göre sentez yönü farklı görünür."},{"t":"Sonuç ikilik","a":"Öncül ve kesintili","d":"Çatalla aynı yöne uzayan iplik kesintisiz (öncül), tersine uzayan iplik parçalı (kesintili) sentezlenir. Böylece tek çatalda iki farklı sentez biçimi ortaya çıkar."}],"ans":"Kalıplar antiparalel, polimeraz 5'→3' tek yönlü olduğundan biri öncül biri kesintili sentezlenir"},{"q":"Kesintili ipliğin tamamlanma sürecini RNA primer, polimeraz ve ligaz görevleriyle adım adım açıklayınız.","steps":[{"t":"Başlatma","a":"Primaz primer kurar","d":"Primaz her Okazaki parçası için kısa bir RNA primeri sentezler. Bu primer serbest 3'-OH ucu sağlar."},{"t":"Uzatma","a":"Polimeraz parça kurar","d":"DNA polimeraz primerin ucundan başlayıp bir önceki parçanın başına kadar DNA sentezler. Böylece her Okazaki parçası oluşur."},{"t":"Primer çıkarma ve doldurma","a":"RNA yerine DNA","d":"RNA primerleri çıkarılıp yerleri DNA nükleotidleriyle doldurulur. Geriye yalnızca parçalar arası çentikler kalır."},{"t":"Birleştirme","a":"Ligaz bağlar","d":"DNA ligaz çentikleri fosfodiester bağıyla kapatarak parçaları birleştirir. Sonuçta kesintili iplik sürekli bir DNA hâline gelir."}],"ans":"Primaz primer kurar, polimeraz uzatır, primer DNA ile değişir, ligaz çentikleri kapatır"},{"q":"Replikasyonun yarı korunumlu doğasının Meselson-Stahl benzeri bir deneyle neden ortaya konabileceğini açıklayınız.","steps":[{"t":"İplikler etiketlenir","a":"Ağır ve hafif iplik","d":"Eski ipliklere ağır, yeni ipliklere hafif yapı taşı işareti konulduğu varsayılır. Böylece eski ve yeni iplikler ayırt edilebilir."},{"t":"İlk kuşak melez","a":"Bir eski bir yeni","d":"Yarı korunumlu modelde ilk eşlenmeden sonra her DNA bir ağır bir hafif iplik taşır, yani melez yoğunlukta olur. Bu sonuç korunumlu modeli eler."},{"t":"Sonraki kuşak ayrışır","a":"Melez ve hafif karışım","d":"İkinci eşlenmede melez ve tamamen hafif DNA'lar birlikte görülür. Bu dağılım yalnızca yarı korunumlu modelle açıklanır."}],"ans":"İlk kuşakta tümü melez, ikinci kuşakta melez+hafif çıkması yarı korunumu kanıtlar"},{"q":"Helikaz, SSB benzeri proteinler ve topoizomeraz aktivitesinin çatal ilerleyişindeki uyumunu açıklayınız.","steps":[{"t":"Helikaz açar","a":"İplikleri ayırır","d":"Helikaz hidrojen bağlarını çözerek çatalı ilerletir. Ancak bu açılma iki yan etki doğurur."},{"t":"Tek iplik korunur","a":"SSB açık tutar","d":"Açılan tek iplikler tekrar birleşmesin diye tek iplik bağlayıcı proteinler onları kaplar. Böylece kalıplar erişilebilir kalır."},{"t":"Burulma giderilir","a":"Topoizomeraz gevşetir","d":"Çatalın önünde biriken aşırı sarılma topoizomeraz tarafından gevşetilir. Bu üç etkinlik birlikte çalışınca çatal düzgün ilerler."}],"ans":"Helikaz açar, SSB iplikleri açık tutar, topoizomeraz burulmayı giderir; üçü uyumla ilerler"},{"q":"DNA polimerazın serbest 3'-OH zorunluluğu, hücrede neden ayrı bir primaz enzimine gereksinim doğurur?","steps":[{"t":"Polimeraz başlatamaz","a":"De novo sentez yok","d":"DNA polimeraz var olan bir 3'-OH ucuna ekleme yapar ama sıfırdan iplik başlatamaz. Yani de novo sentez yapamaz."},{"t":"Başlatıcı gerekir","a":"Primer 3'-OH sağlar","d":"Sentezin başlaması için bir serbest 3'-OH ucu sunan başlatıcı gerekir. Bu başlatıcı kısa bir RNA primeridir."},{"t":"Primaz devreye girer","a":"RNA primeri sentezler","d":"Primaz, polimerazın aksine kalıp üzerinde sıfırdan RNA sentezleyebilir. Böylece polimerazın ihtiyaç duyduğu başlangıcı sağlar."}],"ans":"Polimeraz de novo başlatamadığından primaz başlatıcı RNA primerini sağlamak için gereklidir"},{"q":"Öncül iplikte tek, kesintili iplikte çok sayıda primer bulunmasının yapısal nedenini açıklayınız.","steps":[{"t":"Öncül süreklilik","a":"Tek başlatma yeter","d":"Öncül iplik çatalla aynı yönde kesintisiz uzadığı için yalnızca bir kez başlatılması yeterlidir. Bu nedenle tek primer kullanılır."},{"t":"Kesintili parçalılık","a":"Her parça yeni başlangıç","d":"Kesintili iplik çatalın açılma yönünün tersine parçalar hâlinde sentezlenir. Her yeni Okazaki parçası ayrı bir başlangıç noktası gerektirir."},{"t":"Sonuç","a":"Çok primer oluşur","d":"Bu yüzden kesintili iplikte her parça için bir RNA primeri sentezlenir ve çok sayıda primer bulunur. Öncül iplikte ise tek primer yeterlidir."}],"ans":"Öncül kesintisiz olduğundan tek, kesintili her Okazaki parçası için ayrı primer gerektirdiğinden çok primer kullanır"},{"q":"Replikasyon çatalında primerlerin RNA olmasının ve sonradan DNA ile değiştirilmesinin işlevsel mantığı nedir?","steps":[{"t":"RNA hızlı başlatır","a":"Primaz RNA kurar","d":"Hücre, sentezi hızla başlatmak için RNA primeri kullanır çünkü primaz kalıp üzerinde doğrudan RNA sentezleyebilir. Bu, başlatma sorununu çözer."},{"t":"RNA hatalıdır","a":"Düşük doğruluk","d":"Ancak RNA primerleri kalıcı kalsa DNA içinde yabancı ve daha hatalı bir parça oluşurdu. Bu, genetik bilginin güvenilirliğini bozardı."},{"t":"DNA ile değiştirilir","a":"Primer çıkarılır","d":"Bu yüzden primerler çıkarılıp yerleri DNA ile doldurulur ve ligaz bağlar. Böylece hem hızlı başlatma hem yüksek doğruluk sağlanır."}],"ans":"RNA hızlı başlatma sağlar, sonradan DNA ile değiştirilerek molekülün tamamı DNA ve yüksek doğrulukta olur"},{"q":"İki yönlü ilerleyen bir replikasyon orijininde iki çatalın aynı anda çalışmasının avantajı nedir?","steps":[{"t":"Orijin açılır","a":"İki çatal oluşur","d":"Replikasyon başlangıç noktasından (orijin) iki yöne doğru iki ayrı çatal açılır. Her çatal zıt yönlerde ilerler."},{"t":"Eşzamanlı sentez","a":"Aynı anda kopyalanır","d":"İki çatal aynı bölgeyi farklı yönlerden kopyaladığı için eşlenme alanı iki katına çıkar. Bu, bekleme süresini azaltır."},{"t":"Hız kazanımı","a":"Süre kısalır","d":"Böylece uzun bir DNA daha kısa sürede eşlenir. İki yönlü ilerleme replikasyon hızını belirgin biçimde artırır."}],"ans":"İki çatal aynı anda zıt yönlerde çalışarak eşlenme süresini kısaltır"},{"q":"DNA polimerazın okuma-düzeltme (proofreading) yeteneği replikasyon çatalında nasıl bir katkı sağlar?","steps":[{"t":"Yanlış nükleotid","a":"Eşleşme hatası","d":"Sentez sırasında bazen yanlış bir nükleotid eklenebilir. Bu, kalıpla eşleşmeyen bir baz çifti oluşturur."},{"t":"Polimeraz fark eder","a":"Hatalı bazı keser","d":"DNA polimeraz yanlış eşleşmeyi fark ederek hatalı nükleotidi geri çıkarır. Ardından doğru olanı ekler."},{"t":"Doğruluk artar","a":"Hata oranı düşer","d":"Bu okuma-düzeltme sayesinde replikasyonun hata oranı çok düşük kalır. Böylece genetik bilgi yüksek doğrulukla korunur."}],"ans":"Yanlış eklenen nükleotidi çıkarıp doğrusunu koyarak replikasyon doğruluğunu artırır"},{"q":"Antiparalel yapı olmasaydı (iplikler paralel olsaydı) replikasyonda hangi temel zorluk ortadan kalkardı?","steps":[{"t":"Mevcut durum","a":"Antiparalel kalıplar","d":"Gerçekte iki kalıp antiparalel olduğu için polimeraz birinde çatalı izler, diğerinde tersine çalışmak zorunda kalır. Bu da kesintili sentezi doğurur."},{"t":"Varsayım","a":"İplikler paralel olsaydı","d":"İplikler paralel olsaydı her iki kalıp da aynı yönde uzanırdı. Polimeraz her ikisini de çatalı izleyerek kesintisiz sentezleyebilirdi."},{"t":"Sonuç","a":"Kesintili iplik gerekmezdi","d":"Bu durumda Okazaki parçaları, çok primer ve ligaz gereksinimi büyük ölçüde ortadan kalkardı. Yani kesintili sentez sorunu yaşanmazdı."}],"ans":"Kesintili (Okazaki parçaları hâlinde) sentez gereksinimi ortadan kalkardı"},{"q":"Replikasyon çatalında helikaz hızının primaz ve polimeraz aktivitesiyle eşgüdümlü olmasının önemini açıklayınız.","steps":[{"t":"Açma sentezi besler","a":"Kalıp sağlanır","d":"Helikaz açtıkça polimeraz ve primaz için yeni kalıp ortaya çıkar. Sentez ancak açılmış bölgede yürüyebilir."},{"t":"Aşırı açma riski","a":"Korumasız iplik","d":"Helikaz sentezden çok hızlı giderse uzun korumasız tek iplik birikir. Bu da hasara ve hatalara açık bölgeler oluşturur."},{"t":"Eşgüdüm gerekir","a":"Hızlar uyumlu olmalı","d":"Bu yüzden açma ve sentez hızlarının uyumlu olması gerekir. Eşgüdüm, hem verimli hem güvenli bir eşlenme sağlar."}],"ans":"Açma ve sentez hızları uyumlu olmazsa korumasız tek iplik birikir; eşgüdüm verim ve güvenliği sağlar"},{"q":"Bir Okazaki parçasının başından sonuna kadar geçirdiği moleküler aşamaları sıralayınız.","steps":[{"t":"Primer","a":"RNA başlatıcı","d":"Primaz, kesintili iplik kalıbına kısa bir RNA primeri sentezler. Bu primer parçanın başlangıcını oluşturur."},{"t":"Uzama","a":"DNA eklenir","d":"DNA polimeraz primerin 3' ucundan başlayarak DNA nükleotidleri ekler. Parça bir önceki Okazaki parçasının başına kadar uzar."},{"t":"Primer değişimi","a":"RNA çıkar DNA gelir","d":"RNA primeri çıkarılır ve yerine DNA nükleotidleri doldurulur. Geriye yalnızca bir çentik kalır."},{"t":"Bağlama","a":"Ligaz birleştirir","d":"DNA ligaz çentiği fosfodiester bağıyla kapatır. Böylece parça komşu parçaya bağlanır ve iplik bütünleşir."}],"ans":"RNA primeri, DNA uzaması, primerin DNA ile değişimi, ligazla bağlanma"},{"q":"Replikasyon çatalında öncül ve kesintili ipliklerin tek bir polimeraz kompleksiyle eşzamanlı yürütülebilmesi için kalıbın nasıl yönlendirilmesi gerekir?","steps":[{"t":"Sorun","a":"İplikler zıt yönde","d":"Öncül ve kesintili kalıplar antiparaleldir, yani sentez yönleri birbirine terstir. Tek kompleksin ikisini birlikte yürütmesi bu yüzden zordur."},{"t":"Çözüm","a":"Kesintili kalıp ilmek yapar","d":"Kesintili iplik kalıbı bir ilmek (loop) oluşturacak şekilde bükülür. Böylece her iki kalıp da polimerazda aynı yöne doğru beslenir."},{"t":"Sonuç","a":"Eşzamanlı sentez","d":"İlmek sayesinde tek kompleks hem öncül hem kesintili ipliği aynı anda sentezleyebilir. Bu düzen eşlenmeyi düzenli ve verimli kılar."}],"ans":"Kesintili iplik kalıbının ilmek (loop) yapması, böylece her iki kalıbın aynı yönde beslenmesi"},{"q":"Replikasyonun S evresinde gerçekleşmesi ve hücre döngüsüyle eşgüdümlü olması neden önemlidir?","steps":[{"t":"S evresi","a":"DNA bu evrede eşlenir","d":"Hücre döngüsünde DNA replikasyonu yalnızca S (sentez) evresinde gerçekleşir. Bu, eşlenmenin denetimli bir zamana sıkıştırılmasını sağlar."},{"t":"Tam ve tek kopya","a":"Bir kez eşlenir","d":"Eşgüdüm sayesinde DNA bölünmeden önce tam olarak ve yalnızca bir kez kopyalanır. Eksik veya fazla kopyalama önlenir."},{"t":"Doğru bölünme","a":"Eşit dağılım","d":"Böylece mitoz sırasında her yavru hücreye tam bir kromozom takımı düşer. Bu da kalıtsal kararlılığı korur."}],"ans":"DNA'nın bölünmeden önce tam ve yalnızca bir kez kopyalanmasını sağlayarak yavru hücrelere eşit dağıtımı güvence altına alır"},{"q":"Telomer benzeri uç bölgelerin standart replikasyon mekanizmasıyla tamamen kopyalanamamasının nedenini açıklayınız.","steps":[{"t":"Kesintili iplik ucu","a":"Son primer sorunu","d":"Kesintili iplikte en uçtaki Okazaki parçası bir RNA primeri ile başlar. Bu uçtaki primer çıkarıldığında, yerini dolduracak 3' uç bulunmaz."},{"t":"Doldurulamayan boşluk","a":"Uç kısalır","d":"Polimeraz boşluğu dolduramaz çünkü ekleyebileceği serbest bir 3'-OH yoktur. Böylece her eşlenmede uçta küçük bir boşluk kalır."},{"t":"Sonuç","a":"Uçtan kısalma","d":"Bu nedenle doğrusal kromozomlar her replikasyonda uçlarından bir miktar kısalır. Telomerler bu kısalmaya karşı tampon bölge görevi görür."}],"ans":"Uçtaki RNA primeri çıkarılınca doldurulacak 3'-OH bulunmadığından uçta boşluk kalır ve kromozom uçtan kısalır"}]}},"rnaYapi":{"ilkokul":{"kolay":[{"q":"RNA molekülü kaç iplikten oluşur?","steps":[{"t":"DNA ile karşılaştır","a":"DNA iki ipliklidir","d":"DNA molekülü birbirine sarılı iki iplikten oluşur. RNA ise farklı bir yapıya sahiptir."},{"t":"RNA tek ipliklidir","a":"Tek iplik vardır","d":"RNA genellikle tek bir iplikten oluşur. Yani DNA gibi çift sarmal değildir."}],"ans":"Tek iplik"},{"q":"RNA'nın yapısında bulunan şekerin adı nedir?","steps":[{"t":"DNA şekeri","a":"DNA'da deoksiriboz","d":"DNA'nın yapısında deoksiriboz adlı şeker bulunur. RNA'da ise farklı bir şeker vardır."},{"t":"RNA şekeri","a":"RNA'da riboz","d":"RNA'nın yapısında riboz adlı şeker bulunur. Bu şeker RNA'yı DNA'dan ayıran özelliklerden biridir."}],"ans":"Riboz"},{"q":"RNA'da timin bazının yerini hangi baz alır?","steps":[{"t":"DNA'da timin var","a":"DNA timin içerir","d":"DNA'nın yapısında timin adlı bir baz bulunur. RNA'da bu baz yer almaz."},{"t":"RNA'da urasil var","a":"Yerine urasil gelir","d":"RNA'da timin yerine urasil bazı bulunur. Yani RNA'da urasil timinin yerini alır."}],"ans":"Urasil"},{"q":"Mesaj taşıyan RNA çeşidinin kısa adı nedir?","steps":[{"t":"RNA çeşitleri var","a":"Farklı RNA türleri","d":"Hücrede farklı görevler için farklı RNA çeşitleri bulunur. Bunlardan biri mesaj taşır."},{"t":"Mesajcı RNA","a":"mRNA mesaj taşır","d":"DNA'daki bilgiyi taşıyan RNA çeşidine mesajcı RNA, yani mRNA denir. Bu RNA bilgiyi ribozoma götürür."}],"ans":"mRNA"},{"q":"RNA mı yoksa DNA mı genellikle daha uzun bir moleküldür?","steps":[{"t":"DNA tüm bilgiyi taşır","a":"DNA çok uzundur","d":"DNA, canlının bütün genetik bilgisini taşıdığı için çok uzun bir moleküldür. İçinde binlerce gen bulunur."},{"t":"RNA daha kısadır","a":"RNA kısa bir kopyadır","d":"RNA ise genellikle DNA'nın küçük bir bölümünün kopyasıdır. Bu yüzden DNA'dan daha kısadır."}],"ans":"DNA"}],"zor":[{"q":"RNA'nın tek iplikli olması onu DNA'dan hangi yönüyle ayırır?","steps":[{"t":"DNA çift sarmal","a":"İki iplik sarılı","d":"DNA iki ipliğin birbirine sarılmasıyla oluşan çift sarmal yapıya sahiptir. Bu yapı onu sağlam kılar."},{"t":"RNA tek iplik","a":"Tek iplik serbest","d":"RNA tek iplikli olduğu için kıvrılıp farklı şekiller alabilir. Bu da onu DNA'dan ayıran bir farktır."}],"ans":"RNA tek iplikli, DNA ise çift ipliklidir"},{"q":"Bir hücrede tRNA'nın temel görevi nedir?","steps":[{"t":"Protein yapı taşları","a":"Amino asitler gerekir","d":"Proteinler amino asit denen yapı taşlarından oluşur. Bu amino asitlerin ribozoma taşınması gerekir."},{"t":"tRNA taşır","a":"Taşıyıcı RNA görevi","d":"tRNA, yani taşıyıcı RNA, amino asitleri ribozoma taşır. Böylece protein yapımına katkı sağlar."}],"ans":"Amino asitleri ribozoma taşımak"},{"q":"mRNA bilgiyi nereden alıp nereye götürür?","steps":[{"t":"Bilgi DNA'dadır","a":"DNA bilgiyi tutar","d":"Hücredeki genetik bilgi DNA'da saklıdır. Bu bilginin protein yapımı için kullanılması gerekir."},{"t":"mRNA götürür","a":"Ribozoma taşır","d":"mRNA bu bilgiyi DNA'dan alır ve ribozoma götürür. Ribozom bu bilgiyi kullanarak protein yapar."}],"ans":"DNA'dan alıp ribozoma götürür"},{"q":"RNA çeşitlerinden hangisi ribozomun yapısına katılır?","steps":[{"t":"Ribozom yapısı","a":"Ribozom RNA içerir","d":"Ribozom, protein üretiminin yapıldığı bir hücre yapısıdır. Yapısında protein ve özel bir RNA bulunur."},{"t":"rRNA katılır","a":"Ribozomal RNA","d":"Ribozomun yapısına katılan RNA çeşidine rRNA, yani ribozomal RNA denir. Ribozomun çalışmasına yardımcı olur."}],"ans":"rRNA (ribozomal RNA)"},{"q":"RNA'nın yapısında DNA'dan farklı olan iki temel özellik nedir?","steps":[{"t":"Şeker farkı","a":"Riboz bulunur","d":"RNA'da DNA'daki deoksiriboz yerine riboz şekeri bulunur. Bu, ilk önemli farktır."},{"t":"Baz farkı","a":"Urasil bulunur","d":"Ayrıca RNA'da timin yerine urasil bazı yer alır. Şeker ve baz farkı RNA'yı DNA'dan ayırır."}],"ans":"Riboz şekeri bulunması ve timin yerine urasil olması"}]},"ortaokul":{"kolay":[{"q":"RNA'da bulunan riboz şekeri ile DNA'daki deoksiriboz arasındaki temel fark nedir?","steps":[{"t":"Oksijen sayısı","a":"Bir oksijen farkı","d":"Riboz ve deoksiriboz birbirine çok benzer ama bir farkları vardır. Deoksiribozda bir oksijen atomu eksiktir."},{"t":"Riboz daha fazla O içerir","a":"Riboz oksijenli","d":"Riboz şekeri deoksiriboza göre fazladan bir oksijen taşır. Bu küçük fark RNA ile DNA'yı ayırır."}],"ans":"Ribozda fazladan bir oksijen bulunması"},{"q":"mRNA, DNA'daki hangi işlem sonucunda oluşur?","steps":[{"t":"DNA kalıp olur","a":"Bilgi kopyalanır","d":"mRNA, DNA'nın bir bölümünün kopyalanmasıyla oluşur. Bu işlemde DNA kalıp olarak kullanılır."},{"t":"Transkripsiyon","a":"RNA sentezi","d":"DNA'dan RNA üretilmesi işlemine transkripsiyon (yazılım) denir. Bu işlem sonucunda mRNA oluşur."}],"ans":"Transkripsiyon (yazılım)"},{"q":"tRNA hangi molekülleri ribozoma taşır?","steps":[{"t":"Protein yapı taşı","a":"Amino asitler","d":"Proteinler amino asitlerin birleşmesiyle oluşur. Bu amino asitlerin protein sentezi için ribozoma getirilmesi gerekir."},{"t":"tRNA taşır","a":"Taşıyıcı görevi","d":"tRNA uygun amino asitleri ribozoma taşır. Her tRNA belirli bir amino asidi taşımakla görevlidir."}],"ans":"Amino asitleri"},{"q":"rRNA hücrede hangi yapının bileşeni olarak görev yapar?","steps":[{"t":"Protein üretim merkezi","a":"Ribozom yapısı","d":"Hücrede proteinler ribozom adlı yapıda üretilir. Ribozom protein ve RNA'dan oluşur."},{"t":"rRNA ribozomda","a":"Ribozomal bileşen","d":"rRNA ribozomun temel yapı bileşenidir ve onun çalışmasını sağlar. Bu yüzden ribozomal RNA olarak adlandırılır."}],"ans":"Ribozomun (protein sentez merkezinin)"},{"q":"RNA'nın baz çeşitlerinde adenin, guanin ve sitozinin yanında dördüncü baz hangisidir?","steps":[{"t":"Ortak bazlar","a":"A, G, C ortaktır","d":"Adenin, guanin ve sitozin hem DNA hem RNA'da bulunur. Dördüncü baz ikisinde farklıdır."},{"t":"RNA'da urasil","a":"Urasil dördüncü baz","d":"RNA'da dördüncü baz urasildir. DNA'da bu yerde timin bulunur."}],"ans":"Urasil"}],"zor":[{"q":"RNA çeşitlerinin (mRNA, tRNA, rRNA) protein sentezindeki görev bölüşümünü açıklayınız.","steps":[{"t":"Bilgi taşıma","a":"mRNA mesaj getirir","d":"mRNA, DNA'daki gen bilgisini ribozoma taşıyan mesajcıdır. Hangi proteinin yapılacağı bilgisini sağlar."},{"t":"Yapı taşı taşıma","a":"tRNA amino asit getirir","d":"tRNA uygun amino asitleri ribozoma taşır. mRNA'daki şifreye göre doğru amino asidi getirir."},{"t":"Üretim yeri","a":"rRNA ribozomu kurar","d":"rRNA ribozomun yapısını oluşturur ve protein birleşimini gerçekleştirir. Üç RNA birlikte çalışarak protein üretir."}],"ans":"mRNA bilgiyi taşır, tRNA amino asit getirir, rRNA ribozomu oluşturup üretimi yapar"},{"q":"RNA'nın DNA'dan üç temel farkını sıralayınız.","steps":[{"t":"İplik sayısı","a":"RNA tek iplikli","d":"DNA çift iplikli (çift sarmal) iken RNA tek ipliklidir. Bu, ilk temel farktır."},{"t":"Şeker farkı","a":"RNA'da riboz","d":"DNA'da deoksiriboz, RNA'da ise riboz şekeri bulunur. Bu, ikinci farktır."},{"t":"Baz farkı","a":"RNA'da urasil","d":"DNA'da timin bulunurken RNA'da onun yerine urasil yer alır. Bu da üçüncü temel farktır."}],"ans":"Tek iplikli olması, riboz şekeri taşıması ve timin yerine urasil bulundurması"},{"q":"mRNA'nın geçici, DNA'nın ise kalıcı bir molekül olmasının mantığı nedir?","steps":[{"t":"DNA arşivdir","a":"Bilgi saklanır","d":"DNA, canlının tüm genetik bilgisini uzun süre koruyan bir arşivdir. Bu yüzden kalıcı ve sağlam olması gerekir."},{"t":"mRNA kopyadır","a":"Geçici mesaj","d":"mRNA ise DNA'dan alınan geçici bir kopyadır ve görevini yapınca parçalanır. Böylece hücre ihtiyaca göre üretim yapabilir."}],"ans":"DNA bilgiyi kalıcı saklar, mRNA ise işi bitince parçalanan geçici bir kopyadır"},{"q":"tRNA'nın belirli bir amino asidi tanıyıp taşımasının protein sentezi için önemi nedir?","steps":[{"t":"Şifre eşleşmesi","a":"mRNA'yı okur","d":"tRNA, mRNA'daki üçlü şifreye uygun bölgesiyle eşleşir. Böylece doğru yere bağlanır."},{"t":"Doğru amino asit","a":"Uygun yapı taşı","d":"Her tRNA, taşıdığı amino asidi şifreye göre doğru sıraya yerleştirir. Yanlış taşıma proteinin yapısını bozar."}],"ans":"Doğru amino asidin doğru sıraya yerleşmesini sağlayarak proteinin doğru yapılmasını güvence altına alır"},{"q":"RNA'nın tek iplikli olması, onun farklı şekiller alıp çeşitli görevler üstlenmesini nasıl mümkün kılar?","steps":[{"t":"Serbest iplik","a":"Kıvrılabilir yapı","d":"RNA tek iplikli olduğu için kendi üzerine kıvrılabilir. Bu sayede özel üç boyutlu şekiller oluşturabilir."},{"t":"Göreve uygun şekil","a":"İşlevsel yapı","d":"Aldığı şekle göre tRNA taşıma, rRNA ise ribozom yapımı gibi farklı görevler üstlenir. Tek iplikli olması bu çeşitliliği sağlar."}],"ans":"Tek iplikli yapı kendi üzerine kıvrılarak göreve uygun şekiller oluşturmasını sağlar"}]},"lise":{"kolay":[{"q":"RNA'nın nükleotid yapısındaki üç bileşen nedir?","steps":[{"t":"Şeker","a":"Riboz bulunur","d":"RNA nükleotidinin merkezinde riboz şekeri yer alır. Bu beş karbonlu şeker yapının iskeletini oluşturur."},{"t":"Fosfat ve baz","a":"Fosfat ve azotlu baz","d":"Riboza bir fosfat grubu ve bir azotlu organik baz bağlanır. Böylece RNA nükleotidi üç bileşenden oluşur."}],"ans":"Riboz şekeri, fosfat grubu ve azotlu baz"},{"q":"RNA'nın azotlu bazlarında timin yerine urasilin bulunması neyi gösterir?","steps":[{"t":"DNA'da timin","a":"DNA timin içerir","d":"DNA'nın pirimidin bazları sitozin ve timindir. Timin DNA'ya özgüdür."},{"t":"RNA'da urasil","a":"Urasil pirimidindir","d":"RNA'da timin yerine yine bir pirimidin olan urasil bulunur. Bu, RNA ile DNA'yı ayıran bir özelliktir."}],"ans":"RNA'da timinin yerini urasilin aldığını"},{"q":"mRNA'nın protein sentezindeki rolü nedir?","steps":[{"t":"Bilgi kaynağı","a":"DNA'dan kopyalanır","d":"mRNA, transkripsiyonla DNA'daki gen bilgisinin kopyalanmasıyla oluşur. Böylece gen bilgisini taşıyan bir molekül hâline gelir."},{"t":"Şifre taşıma","a":"Ribozoma götürür","d":"mRNA bu bilgiyi kodonlar hâlinde ribozoma taşır. Ribozom bu şifreye göre amino asit dizisini belirler."}],"ans":"Gen bilgisini kodonlar hâlinde ribozoma taşımak"},{"q":"tRNA'nın yapısındaki antikodon bölgesinin işlevi nedir?","steps":[{"t":"mRNA kodonu","a":"Üçlü şifre","d":"mRNA üzerindeki her üçlü baz dizisine kodon denir. Bu kodonlar hangi amino asidin geleceğini belirtir."},{"t":"Antikodon eşleşir","a":"Kodonla bağlanır","d":"tRNA'nın antikodon bölgesi mRNA kodonuyla baz eşleşmesi yapar. Böylece doğru amino asit doğru sıraya gelir."}],"ans":"mRNA kodonuyla eşleşerek doğru amino asidin yerleşmesini sağlamak"},{"q":"rRNA'nın ribozomdaki temel işlevi nedir?","steps":[{"t":"Ribozom bileşeni","a":"Yapısal rol","d":"rRNA, proteinlerle birlikte ribozomun yapısını oluşturur. Ribozomun büyük ve küçük alt birimlerinde bulunur."},{"t":"Üretime katkı","a":"Peptit bağı kurar","d":"rRNA amino asitler arasında peptit bağı kurulmasına yardımcı olur. Böylece protein sentezini gerçekleştirir."}],"ans":"Ribozomun yapısını oluşturup peptit bağı kurulmasına katkı sağlamak"},{"q":"RNA'nın hücredeki yaşam süresi neden genellikle DNA'dan kısadır?","steps":[{"t":"Geçici görev","a":"İşlevsel kopya","d":"RNA çoğunlukla belirli bir iş için üretilen geçici bir moleküldür. Görevi tamamlanınca hücrede kalmasına gerek kalmaz."},{"t":"Parçalanma","a":"Hızla yıkılır","d":"Görevi biten RNA enzimlerle parçalanır. DNA ise kalıcı bilgi deposu olduğu için uzun süre korunur."}],"ans":"RNA geçici işlevli olduğundan görevi bitince parçalanır, DNA ise kalıcı bilgi deposudur"},{"q":"Ribozda 2' karbonunda hidroksil (OH) grubu bulunması RNA'yı nasıl etkiler?","steps":[{"t":"Yapısal fark","a":"2'-OH grubu","d":"RNA'nın riboz şekerinde 2' karbonunda bir hidroksil grubu bulunur. DNA'nın deoksiribozunda bu grup yoktur."},{"t":"Kararlılık","a":"RNA daha kararsız","d":"2'-OH grubu RNA'yı kimyasal olarak daha tepkin ve kararsız yapar. Bu da RNA'nın DNA'ya göre daha çabuk parçalanmasına yol açar."}],"ans":"2'-OH grubu RNA'yı daha tepkin ve kararsız hâle getirir"},{"q":"mRNA üzerindeki kodon kavramını açıklayınız.","steps":[{"t":"Üçlü diziler","a":"Üç baz bir kodon","d":"mRNA üzerindeki ardışık üç azotlu baz bir kodon oluşturur. Her kodon belirli bir bilgi taşır."},{"t":"Amino asit şifresi","a":"Bir amino asidi belirtir","d":"Her kodon genellikle bir amino asidi ya da bir durdurma sinyalini şifreler. Kodonlar sayesinde protein dizisi belirlenir."}],"ans":"mRNA'da bir amino asidi belirten üçlü baz dizisi"},{"q":"RNA'nın tek iplikli olmasına rağmen iç bölgelerinde baz eşleşmeleri görülmesi nasıl açıklanır?","steps":[{"t":"Kendi üzerine katlanma","a":"İplik kıvrılır","d":"RNA tek iplikli olsa da kendi üzerine katlanabilir. Katlanma sırasında ipliğin farklı bölgeleri karşı karşıya gelir."},{"t":"İç eşleşme","a":"Saç tokası yapısı","d":"Karşı gelen tamamlayıcı bazlar arasında eşleşme oluşarak saç tokası gibi yapılar meydana gelir. Bu, tRNA gibi RNA'ların şeklini belirler."}],"ans":"RNA kendi üzerine katlanıp tamamlayıcı bölgeler arasında baz eşleşmesi yapabilir"},{"q":"Hücrede en çok bulunan RNA çeşidinin rRNA olmasının sebebi nedir?","steps":[{"t":"Ribozom bolluğu","a":"Çok ribozom gerekir","d":"Hücre sürekli protein üretmek için çok sayıda ribozoma ihtiyaç duyar. Her ribozom rRNA içerir."},{"t":"rRNA payı","a":"En yüksek oran","d":"Ribozomların yapı taşı olduğu için rRNA hücredeki toplam RNA'nın en büyük bölümünü oluşturur. Bu yüzden en bol RNA çeşididir."}],"ans":"Çok sayıda ribozomun yapısına katıldığı için rRNA en bol RNA çeşididir"},{"q":"mRNA'nın bilgi taşıyıcı, tRNA'nın adaptör (uyarlayıcı) olarak adlandırılmasının nedeni nedir?","steps":[{"t":"mRNA bilgi","a":"Şifreyi taşır","d":"mRNA, gen bilgisini kodonlar hâlinde taşıdığı için bilgi taşıyıcı olarak adlandırılır. Hangi proteinin yapılacağını bildirir."},{"t":"tRNA uyarlama","a":"Şifreyi amino asitle eşler","d":"tRNA, mRNA'daki kodonu uygun amino asitle eşleştirir. Bilgi ile yapı taşını birbirine bağladığı için adaptör denir."}],"ans":"mRNA şifreyi taşır, tRNA kodonu amino asitle eşleştirip uyarladığı için adaptör denir"},{"q":"RNA polimerazın transkripsiyonda DNA polimerazdan farklı olarak primer gerektirmemesi neyi gösterir?","steps":[{"t":"RNA polimeraz başlatır","a":"Primer gerekmez","d":"RNA polimeraz kalıp üzerinde sentezi doğrudan başlatabilir. DNA polimerazın aksine bir başlatıcıya ihtiyaç duymaz."},{"t":"De novo yetenek","a":"Sıfırdan sentez","d":"Bu, RNA polimerazın de novo (sıfırdan) sentez yapabildiğini gösterir. Aynı yetenek primaz enziminde de görülür."}],"ans":"RNA polimerazın de novo (sıfırdan, primersiz) sentez yapabildiğini"},{"q":"RNA çeşitlerinin tümünün DNA'dan üretilmesi neyi ifade eder?","steps":[{"t":"DNA kalıp","a":"Tüm RNA DNA'dan","d":"mRNA, tRNA ve rRNA'nın hepsi DNA'daki ilgili genlerden transkripsiyonla üretilir. DNA bunların hepsi için kalıp görevi görür."},{"t":"Bilgi akışı","a":"DNA'dan RNA'ya","d":"Bu durum, hücrede bilgi akışının DNA'dan RNA'ya doğru olduğunu gösterir. RNA çeşitleri bu akışın ürünleridir."}],"ans":"Tüm RNA çeşitlerinin DNA'daki genlerden transkripsiyonla üretildiğini"},{"q":"tRNA'nın bir ucunda amino asit, diğer bölgesinde antikodon bulunmasının işlevsel önemi nedir?","steps":[{"t":"İki uçlu görev","a":"İki bağlanma bölgesi","d":"tRNA'nın bir ucu amino asit bağlar, diğer bölgesinde ise antikodon bulunur. Böylece molekülün iki ayrı bağlanma yeteneği vardır."},{"t":"Eşleştirme","a":"Bilgi ile yapı taşı","d":"Antikodon mRNA kodonuyla eşleşirken bağlı amino asit zincire eklenir. Bu çift işlev tRNA'yı bilgi ile yapı taşı arasında köprü yapar."}],"ans":"tRNA'nın bir ucu amino asidi taşırken antikodonu mRNA ile eşleşerek doğru yerleşimi sağlar"},{"q":"RNA'nın hem bilgi taşıyabilmesi hem de enzim benzeri görevler üstlenebilmesi neyi gösterir?","steps":[{"t":"Bilgi yönü","a":"Baz dizisi şifre","d":"RNA'nın baz dizisi tıpkı DNA gibi genetik bilgi taşıyabilir. mRNA bunun açık bir örneğidir."},{"t":"İşlevsel yapı","a":"Katlanıp iş yapar","d":"RNA kendi üzerine katlanarak rRNA gibi peptit bağı kurma görevlerini üstlenebilir. Yani hem bilgi hem işlev taşıyabilen çok yönlü bir moleküldür."}],"ans":"RNA'nın hem bilgi taşıyan hem işlev gören çok yönlü bir molekül olduğunu"}],"zor":[{"q":"RNA'nın riboz şekeri, urasil bazı ve tek iplikli yapısının bir arada onu DNA'dan nasıl ayırdığını açıklayınız.","steps":[{"t":"Şeker","a":"Riboz 2'-OH taşır","d":"RNA'da riboz şekeri bulunur ve 2' karbonunda hidroksil grubu taşır. Bu, deoksiribozdan temel farktır ve molekülü daha tepkin yapar."},{"t":"Baz","a":"Urasil yer alır","d":"RNA'da timin yerine urasil bulunur. Urasil de bir pirimidindir ama metil grubu içermez."},{"t":"İplik","a":"Tek iplikli yapı","d":"RNA tek ipliklidir ve kendi üzerine katlanarak işlevsel şekiller alabilir. Bu üç özellik birlikte RNA'yı DNA'dan kesin biçimde ayırır."}],"ans":"Riboz (2'-OH) şekeri, timin yerine urasil ve tek iplikli yapısının birlikte RNA'yı DNA'dan ayırması"},{"q":"mRNA, tRNA ve rRNA'nın protein sentezindeki görevlerini bir bütün olarak adım adım açıklayınız.","steps":[{"t":"Bilgi getirme","a":"mRNA kodon taşır","d":"mRNA, DNA'dan kopyaladığı gen bilgisini kodonlar hâlinde ribozoma taşır. Hangi amino asitlerin hangi sırada geleceğini belirler."},{"t":"Yapı taşı getirme","a":"tRNA amino asit taşır","d":"tRNA antikodonuyla mRNA kodonuna eşleşip taşıdığı amino asidi zincire ekler. Her kodon için uygun tRNA getirir."},{"t":"Üretim merkezi","a":"rRNA ribozomu kurar","d":"rRNA ribozomun yapısını oluşturur ve amino asitler arasında peptit bağı kurulmasını sağlar. Üç RNA birlikte çalışarak protein zincirini üretir."}],"ans":"mRNA bilgiyi taşır, tRNA amino asitleri getirir, rRNA ribozomu kurup peptit bağlarını oluşturur"},{"q":"RNA'nın 2'-OH grubunun molekülün kararlılığı ve işlevi üzerindeki çift yönlü etkisini açıklayınız.","steps":[{"t":"Kararsızlık","a":"Hidrolize yatkın","d":"2'-OH grubu RNA omurgasını kimyasal olarak daha tepkin yapar ve hidrolize yatkın hâle getirir. Bu nedenle RNA DNA'dan daha çabuk parçalanır."},{"t":"İşlevsellik","a":"Katlanma ve aktiflik","d":"Aynı grup RNA'nın esnek katlanmasına ve bazı RNA'ların enzim benzeri (ribozim) aktivite kazanmasına katkı sağlar. Yani kararsızlık aynı zamanda işlev çeşitliliği getirir."},{"t":"Sonuç","a":"Geçici ama çok yönlü","d":"Bu çift etki RNA'yı geçici fakat çok yönlü bir molekül yapar. DNA kalıcı arşiv iken RNA esnek bir işlev molekülüdür."}],"ans":"2'-OH grubu RNA'yı kararsız (çabuk yıkılan) ama esnek ve işlevsel (ribozim olabilen) kılar"},{"q":"tRNA'nın yonca yaprağı / L şeklindeki üç boyutlu yapısının işleviyle ilişkisini açıklayınız.","steps":[{"t":"Katlanma","a":"İç baz eşleşmeleri","d":"tRNA tek iplikli olmasına rağmen kendi üzerine katlanır ve iç baz eşleşmeleriyle yonca yaprağı, ardından L şekli oluşturur. Bu yapı işlevi için kritiktir."},{"t":"İki uç","a":"Antikodon ve amino asit","d":"L yapısının bir ucunda antikodon, diğer ucunda amino asit bağlanma bölgesi bulunur. Bu iki uç birbirinden uzakta konumlanır."},{"t":"İşlev","a":"Köprü görevi","d":"Bu özel geometri tRNA'nın mRNA kodonuyla eşleşirken amino asidi ribozomdaki uygun yere sunmasını sağlar. Yapı, bilgi ile yapı taşı arasında köprü işlevini mümkün kılar."}],"ans":"Katlanmış L yapısı, antikodon ve amino asit uçlarını uygun konuma getirerek tRNA'nın adaptör işlevini sağlar"},{"q":"mRNA'nın geçici, rRNA ve tRNA'nın ise nispeten kararlı olmasının hücresel mantığını açıklayınız.","steps":[{"t":"mRNA ihtiyaca bağlı","a":"Değişken üretim","d":"mRNA, hangi proteinin ne zaman üretileceğini belirler ve bu ihtiyaç sürekli değişir. Geçici olması hücrenin üretimi hızla ayarlamasını sağlar."},{"t":"tRNA ve rRNA sürekli","a":"Hep gerekli","d":"tRNA ve rRNA ise protein sentezinin her aşamasında sürekli kullanılan araçlardır. Bu yüzden uzun ömürlü ve kararlı olmaları verimlidir."},{"t":"Sonuç","a":"Düzenleme ve verim","d":"Bu fark, hücrenin protein üretimini hem esnek biçimde düzenlemesini hem de araçları yeniden kullanarak enerji tasarrufu yapmasını sağlar. Görev türü kararlılığı belirler."}],"ans":"mRNA değişken üretim için geçici, tRNA-rRNA sürekli kullanılan araçlar olduğundan kararlıdır"},{"q":"RNA polimerazın primer gerektirmeden, DNA polimerazın ise primer gerektirerek sentez yapmasının altında yatan farkı açıklayınız.","steps":[{"t":"RNA polimeraz","a":"De novo başlatır","d":"RNA polimeraz kalıp üzerinde ilk nükleotidi serbest 3'-OH ucu olmadan da yerleştirebilir. Yani sentezi sıfırdan başlatabilir."},{"t":"DNA polimeraz","a":"3'-OH ucu ister","d":"DNA polimeraz yalnızca var olan bir serbest 3'-OH ucuna ekleme yapar ve sentezi başlatamaz. Bu yüzden bir başlatıcıya ihtiyaç duyar."},{"t":"Sonuç","a":"Primer RNA'dan","d":"Bu fark nedeniyle replikasyonda DNA polimeraz için RNA primeri (primaz tarafından) hazırlanır. RNA sentezinde ise böyle bir başlatıcı gerekmez."}],"ans":"RNA polimeraz de novo başlatabildiğinden primer gerekmez, DNA polimeraz 3'-OH ucu zorunluluğu nedeniyle primer ister"},{"q":"Urasilin RNA'da, timinin DNA'da kullanılmasının olası bir biyolojik gerekçesini açıklayınız.","steps":[{"t":"Sitozin bozunması","a":"Urasile dönüşebilir","d":"DNA'da sitozin zamanla kimyasal olarak bozunup urasile dönüşebilir. Bu, hatalı bir baz oluşturur."},{"t":"Timin işareti","a":"Doğal urasil ayrımı","d":"DNA timin kullandığı için, ortaya çıkan herhangi bir urasil \"hatalı\" olarak tanınıp onarılabilir. Böylece bilgi korunur."},{"t":"RNA geçici","a":"Onarım gerekmez","d":"RNA geçici olduğundan böyle bir uzun vadeli koruma gerekmez; ayrıca urasil üretimi enerjice daha ucuzdur. Bu yüzden RNA urasil, DNA ise timin kullanır."}],"ans":"DNA timinle hatalı urasili ayırt edip onarabilir; RNA geçici olduğundan ucuz olan urasili kullanır"},{"q":"RNA'nın tek iplikli yapısının hem bir avantaj hem de bir dezavantaj oluşturmasını örneklerle açıklayınız.","steps":[{"t":"Avantaj","a":"Esnek katlanma","d":"Tek iplikli yapı RNA'nın kendi üzerine katlanıp tRNA, rRNA gibi işlevsel şekiller almasını sağlar. Bu, RNA'ya görev çeşitliliği kazandırır."},{"t":"Dezavantaj","a":"Daha kararsız","d":"Aynı zamanda tek iplikli olması RNA'yı dış etkenlere ve parçalanmaya karşı daha savunmasız bırakır. Bu yüzden uzun süreli bilgi saklamaya uygun değildir."},{"t":"Sonuç","a":"İşlev mi kalıcılık mı","d":"Bu nedenle RNA esnek işlevler için, DNA ise kalıcı bilgi saklama için uygundur. Tek iplikli yapı işlev kazandırırken kalıcılıktan ödün verdirir."}],"ans":"Tek iplik esnek işlevsel şekiller sağlar (avantaj) ama molekülü kararsız ve kısa ömürlü yapar (dezavantaj)"},{"q":"Bilgi akışında DNA → mRNA → protein zincirinin her halkasında RNA çeşitlerinin rolünü açıklayınız.","steps":[{"t":"DNA'dan mRNA'ya","a":"Transkripsiyon","d":"DNA'daki gen, transkripsiyonla mRNA'ya kopyalanır ve bilgi RNA diline aktarılır. mRNA bu bilgiyi ribozoma taşır."},{"t":"mRNA'dan amino asitlere","a":"tRNA eşleştirir","d":"Ribozomda tRNA, mRNA kodonlarına uygun amino asitleri getirir. Bilgi böylece amino asit dizisine çevrilir."},{"t":"Üretim","a":"rRNA peptit bağı kurar","d":"rRNA içeren ribozom amino asitler arasında peptit bağı kurarak protein zincirini oluşturur. Üç RNA çeşidi bilgi akışının her halkasında görev alır."}],"ans":"mRNA bilgiyi kopyalayıp taşır, tRNA kodonu amino asitle eşleştirir, rRNA peptit bağı kurarak proteini üretir"},{"q":"rRNA'nın yalnızca yapısal değil aynı zamanda katalitik (ribozim) bir bileşen olmasının önemini açıklayınız.","steps":[{"t":"Yapısal rol","a":"Ribozomu kurar","d":"rRNA proteinlerle birlikte ribozomun büyük ve küçük alt birimlerini oluşturur. Bu yapı protein sentezinin platformudur."},{"t":"Katalitik rol","a":"Peptit bağı kurar","d":"rRNA aynı zamanda peptit bağı kurma tepkimesini katalizler, yani bir ribozim gibi davranır. Bu işi protein değil RNA yapar."},{"t":"Önem","a":"RNA dünyası kanıtı","d":"rRNA'nın katalitik olması, RNA'nın hem bilgi taşıyıp hem tepkime hızlandırabildiğini gösterir. Bu, yaşamın kökeninde RNA'nın merkezî rol oynamış olabileceğine işaret eder."}],"ans":"rRNA hem ribozomu oluşturur hem peptit bağını katalizler; bu, RNA'nın bilgi+enzim çift yeteneğini kanıtlar"},{"q":"mRNA üzerindeki kodonların üçlü olmasının (ikili değil) genetik şifre açısından gerekliliğini açıklayınız.","steps":[{"t":"Baz sayısı","a":"Dört çeşit baz","d":"mRNA'da dört çeşit baz (A, U, G, C) bulunur. Bunlarla amino asitlerin şifrelenmesi gerekir."},{"t":"Yetersiz seçenekler","a":"İkili 16 kombinasyon","d":"İkili kodon kullanılsa yalnızca 16 farklı kombinasyon olurdu; bu, 20 amino asidi şifrelemeye yetmez. Daha fazla seçenek gerekir."},{"t":"Üçlü çözüm","a":"64 kombinasyon","d":"Üçlü kodon 64 farklı kombinasyon sağlar ve 20 amino asidi rahatça şifreler. Fazla kombinasyonlar ise farklı kodonların aynı amino asidi belirtmesini sağlar."}],"ans":"İkili kodon 16 ile yetersiz kalacağından, 64 kombinasyon sunan üçlü kodon 20 amino asidi şifrelemek için gereklidir"},{"q":"Olgun mRNA'nın oluşumunda primer mRNA'nın işlenmesinin (uç düzenlemeleri ve kesilip-eklenme) işlevsel önemini açıklayınız.","steps":[{"t":"Ön mRNA","a":"İşlenmemiş kopya","d":"Transkripsiyonla önce işlenmemiş bir ön-mRNA üretilir. Bu hâliyle kararsız ve doğrudan kullanıma uygun değildir."},{"t":"Uç düzenlemeleri","a":"Koruyucu eklemeler","d":"mRNA'nın uçlarına koruyucu yapılar (başlık ve kuyruk) eklenir. Bunlar molekülü kararlı kılar ve ribozomca tanınmasını sağlar."},{"t":"Kesilip eklenme","a":"Kodlamayan bölge çıkarılır","d":"Kodlamayan ara bölgeler çıkarılıp kodlayan bölgeler birleştirilir. Böylece olgun, işlevsel mRNA oluşur ve doğru protein sentezi sağlanır."}],"ans":"İşleme mRNA'yı kararlı kılar, kodlamayan bölgeleri çıkarır ve doğru proteinin sentezlenmesini sağlar"},{"q":"RNA dünyası hipotezi bağlamında RNA'nın hem bilgi hem katalizör olabilmesinin neden önemli olduğunu açıklayınız.","steps":[{"t":"Bilgi taşıma","a":"Baz dizisi kodlar","d":"RNA, baz dizisi sayesinde DNA gibi kalıtsal bilgi taşıyabilir. Bu, kendini kopyalayabilecek bilgi temeli sağlar."},{"t":"Kataliz","a":"Ribozim olabilir","d":"RNA aynı zamanda katlanıp ribozim olarak tepkimeleri hızlandırabilir. Yani enzim görevini de üstlenebilir."},{"t":"Köken senaryosu","a":"Tek molekül yeterli","d":"Bu iki yetenek, erken yaşamda tek bir molekül türünün hem bilgi saklayıp hem tepkime yürütebileceğini gösterir. Böylece DNA ve proteinlerden önce RNA temelli bir yaşam mümkün olur."}],"ans":"RNA hem bilgi saklayıp hem tepkime katalizleyebildiğinden, DNA ve proteinden önce RNA temelli yaşamı mümkün kılar"},{"q":"Bir genden üretilen mRNA'nın kodon dizisi ile karşılık gelen tRNA antikodonları arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Kodon","a":"mRNA üçlüsü","d":"mRNA üzerindeki her üçlü baz dizisi bir kodondur ve bir amino asidi belirtir. Kodonlar 5'→3' yönünde okunur."},{"t":"Antikodon","a":"tRNA tamamlayıcısı","d":"Her tRNA, kodona tamamlayıcı bir antikodon taşır. Antikodon kodonla antiparalel olarak baz eşleşmesi yapar."},{"t":"Eşleşme","a":"Doğru amino asit","d":"Kodon-antikodon eşleşmesi sayesinde her kodon için doğru amino asit getirilir. Böylece mRNA dizisi protein dizisine doğru biçimde çevrilir."}],"ans":"Her mRNA kodonu, tamamlayıcı (antiparalel) antikodon taşıyan tRNA ile eşleşerek doğru amino asidin gelmesini sağlar"},{"q":"RNA'nın hücredeki çeşitliliğinin (mRNA, tRNA, rRNA ve düzenleyici RNA'lar) tek bir DNA kaynağından nasıl ortaya çıktığını açıklayınız.","steps":[{"t":"Tek kaynak","a":"DNA tüm genleri taşır","d":"Hücredeki tüm RNA çeşitlerinin bilgisi DNA'daki ayrı genlerde kayıtlıdır. DNA bunların hepsi için ortak kalıptır."},{"t":"Seçici transkripsiyon","a":"Farklı genler okunur","d":"Farklı genlerden transkripsiyonla farklı RNA'lar üretilir; biri mRNA, biri tRNA, biri rRNA geni olabilir. Hangi genin okunacağı düzenlenir."},{"t":"İşlevsel çeşitlilik","a":"Yapı ve görev farkı","d":"Üretilen her RNA dizisine göre katlanıp farklı yapı ve görevler kazanır. Böylece tek bir DNA kaynağından işlevsel olarak çeşitli RNA'lar ortaya çıkar."}],"ans":"Tüm RNA çeşitleri DNA'daki ayrı genlerden seçici transkripsiyonla üretilir; dizilerine göre farklı yapı ve görev kazanırlar"}]}}};
